static WASMComponentCoreModuleWrapper *
create_core_module_wrapper_from_file(const char *path, const char *module_name,
                                     char *error_buf, uint32_t error_buf_size)
{
    uint32_t wasm_file_size = 0;
    auto *wasm_raw = (unsigned char *)bh_read_file_to_buffer(path, &wasm_file_size);
    auto *core_module = (WASMComponentCoreModuleWrapper *)wasm_runtime_malloc(
        sizeof(WASMComponentCoreModuleWrapper));
    LoadArgs load_args = {};

    if (!wasm_raw || !core_module) {
        if (wasm_raw) {
            BH_FREE(wasm_raw);
        }
        if (core_module) {
            wasm_runtime_free(core_module);
        }
        return nullptr;
    }

    memset(core_module, 0, sizeof(WASMComponentCoreModuleWrapper));
    load_args.name = (char *)module_name;
    core_module->module_handle = wasm_runtime_load_ex(
        wasm_raw, wasm_file_size, &load_args, error_buf, error_buf_size);
    if (!core_module->module_handle) {
        BH_FREE(wasm_raw);
        wasm_runtime_free(core_module);
        return nullptr;
    }
    core_module->owned_binary = wasm_raw;
    core_module->owned_binary_size = wasm_file_size;

    return core_module;
}

static WASMComponentTypeBound *
create_type_bound(WASMComponentTypeBoundTag tag, uint32_t type_idx)
{
    auto *type_bound = (WASMComponentTypeBound *)wasm_runtime_malloc(
        sizeof(WASMComponentTypeBound));
    if (!type_bound) {
        return nullptr;
    }

    type_bound->tag = tag;
    type_bound->type_idx = type_idx;
    return type_bound;
}

static bool
init_resource_type_section(WASMComponentTypeSection *type_section, uint32_t count,
                           bool has_dtor)
{
    if (!type_section || count == 0) {
        return false;
    }

    type_section->count = count;
    type_section->types =
        (WASMComponentTypes *)wasm_runtime_malloc(sizeof(WASMComponentTypes) * count);
    if (!type_section->types) {
        return false;
    }
    memset(type_section->types, 0, sizeof(WASMComponentTypes) * count);

    for (uint32_t i = 0; i < count; i++) {
        auto *resource_type = (WASMComponentResourceType *)wasm_runtime_malloc(
            sizeof(WASMComponentResourceType));
        auto *sync_type = (WASMComponentResourceTypeSync *)wasm_runtime_malloc(
            sizeof(WASMComponentResourceTypeSync));
        if (!resource_type || !sync_type) {
            return false;
        }

        memset(resource_type, 0, sizeof(WASMComponentResourceType));
        memset(sync_type, 0, sizeof(WASMComponentResourceTypeSync));
        sync_type->has_dtor = has_dtor;
        sync_type->dtor_func_idx = 0;
        resource_type->tag = WASM_COMP_RESOURCE_TYPE_SYNC;
        resource_type->resource.sync = sync_type;
        type_section->types[i].tag = WASM_COMP_RESOURCE_TYPE_SYNC;
        type_section->types[i].type.resource_type = resource_type;
    }

    return true;
}

static WASMComponentCoreImportDesc *
create_core_func_import_desc(uint32_t func_type_idx)
{
    auto *import_desc = (WASMComponentCoreImportDesc *)wasm_runtime_malloc(
        sizeof(WASMComponentCoreImportDesc));
    if (!import_desc) {
        return nullptr;
    }

    memset(import_desc, 0, sizeof(WASMComponentCoreImportDesc));
    import_desc->type = WASM_CORE_IMPORTDESC_FUNC;
    import_desc->desc.func_type_idx = func_type_idx;
    return import_desc;
}

static bool
init_single_cabi_realloc_export_core_type_section(
    WASMComponentCoreTypeSection *core_type_section, const char *export_name)
{
    auto *module_type = (WASMComponentCoreModuleType *)wasm_runtime_malloc(
        sizeof(WASMComponentCoreModuleType));
    auto *module_type_decls = (WASMComponentCoreModuleDecl *)wasm_runtime_malloc(
        sizeof(WASMComponentCoreModuleDecl) * 2);
    auto *func_type = (WASMComponentCoreType *)wasm_runtime_malloc(
        sizeof(WASMComponentCoreType));
    auto *func_def_type = (WASMComponentCoreDefType *)wasm_runtime_malloc(
        sizeof(WASMComponentCoreDefType));
    auto *func_subtype = (WASMComponentCoreModuleSubType *)wasm_runtime_malloc(
        sizeof(WASMComponentCoreModuleSubType));
    auto *func_comp_type = (WASMComponentCoreCompType *)wasm_runtime_malloc(
        sizeof(WASMComponentCoreCompType));
    auto *func_params = (WASMComponentCoreValType *)wasm_runtime_malloc(
        sizeof(WASMComponentCoreValType) * 4);
    auto *func_results = (WASMComponentCoreValType *)wasm_runtime_malloc(
        sizeof(WASMComponentCoreValType));
    auto *export_decl = (WASMComponentCoreExportDecl *)wasm_runtime_malloc(
        sizeof(WASMComponentCoreExportDecl));
    auto *module_def_type = (WASMComponentCoreDefType *)wasm_runtime_malloc(
        sizeof(WASMComponentCoreDefType));

    if (!core_type_section || !module_type || !module_type_decls || !func_type
        || !func_def_type || !func_subtype || !func_comp_type || !func_params
        || !func_results || !export_decl || !module_def_type) {
        return false;
    }

    memset(core_type_section, 0, sizeof(WASMComponentCoreTypeSection));
    core_type_section->count = 1;
    core_type_section->types =
        (WASMComponentCoreType *)wasm_runtime_malloc(sizeof(WASMComponentCoreType));
    if (!core_type_section->types) {
        return false;
    }
    memset(core_type_section->types, 0, sizeof(WASMComponentCoreType));

    memset(module_type, 0, sizeof(WASMComponentCoreModuleType));
    memset(module_type_decls, 0, sizeof(WASMComponentCoreModuleDecl) * 2);
    memset(func_type, 0, sizeof(WASMComponentCoreType));
    memset(func_def_type, 0, sizeof(WASMComponentCoreDefType));
    memset(func_subtype, 0, sizeof(WASMComponentCoreModuleSubType));
    memset(func_comp_type, 0, sizeof(WASMComponentCoreCompType));
    memset(func_params, 0, sizeof(WASMComponentCoreValType) * 4);
    memset(func_results, 0, sizeof(WASMComponentCoreValType));
    memset(export_decl, 0, sizeof(WASMComponentCoreExportDecl));
    memset(module_def_type, 0, sizeof(WASMComponentCoreDefType));

    func_params[0].tag = WASM_CORE_VALTYPE_NUM;
    func_params[0].type.num_type = WASM_CORE_NUM_TYPE_I32;
    func_params[1].tag = WASM_CORE_VALTYPE_NUM;
    func_params[1].type.num_type = WASM_CORE_NUM_TYPE_I32;
    func_params[2].tag = WASM_CORE_VALTYPE_NUM;
    func_params[2].type.num_type = WASM_CORE_NUM_TYPE_I32;
    func_params[3].tag = WASM_CORE_VALTYPE_NUM;
    func_params[3].type.num_type = WASM_CORE_NUM_TYPE_I32;
    func_results[0].tag = WASM_CORE_VALTYPE_NUM;
    func_results[0].type.num_type = WASM_CORE_NUM_TYPE_I32;

    func_comp_type->tag = WASM_CORE_COMPTYPE_FUNC;
    func_comp_type->type.func_type.params.count = 4;
    func_comp_type->type.func_type.params.val_types = func_params;
    func_comp_type->type.func_type.results.count = 1;
    func_comp_type->type.func_type.results.val_types = func_results;
    func_subtype->comptype = func_comp_type;

    func_def_type->tag = WASM_CORE_DEFTYPE_SUBTYPE;
    func_def_type->type.subtype = func_subtype;
    func_type->deftype = func_def_type;

    module_type->decl_count = 2;
    module_type->declarations = module_type_decls;
    module_type_decls[0].tag = WASM_CORE_MODULEDECL_TYPE;
    module_type_decls[0].decl.type_decl.type = func_type;
    module_type_decls[1].tag = WASM_CORE_MODULEDECL_EXPORT;
    module_type_decls[1].decl.export_decl.export_decl = export_decl;

    export_decl->name = clone_core_name(export_name);
    export_decl->export_desc = create_core_func_import_desc(0);
    if (!export_decl->name || !export_decl->export_desc) {
        return false;
    }

    module_def_type->tag = WASM_CORE_DEFTYPE_MODULETYPE;
    module_def_type->type.moduletype = module_type;
    core_type_section->types[0].deftype = module_def_type;
    return true;
}

static bool
init_single_instance_type_section(WASMComponentTypeSection *type_section,
                                  const char *export_name,
                                  WASMComponentExternDesc *export_desc)
{
    auto *instance_type =
        (WASMComponentInstType *)wasm_runtime_malloc(sizeof(WASMComponentInstType));
    auto *instance_decls = (WASMComponentInstDecl *)wasm_runtime_malloc(
        sizeof(WASMComponentInstDecl));
    auto *export_decl =
        (WASMComponentComponentDeclExport *)wasm_runtime_malloc(
            sizeof(WASMComponentComponentDeclExport));

    if (!type_section || !export_name || !export_desc || !instance_type
        || !instance_decls || !export_decl) {
        return false;
    }

    memset(type_section, 0, sizeof(WASMComponentTypeSection));
    type_section->count = 1;
    type_section->types =
        (WASMComponentTypes *)wasm_runtime_malloc(sizeof(WASMComponentTypes));
    if (!type_section->types) {
        return false;
    }
    memset(type_section->types, 0, sizeof(WASMComponentTypes));
    memset(instance_type, 0, sizeof(WASMComponentInstType));
    memset(instance_decls, 0, sizeof(WASMComponentInstDecl));
    memset(export_decl, 0, sizeof(WASMComponentComponentDeclExport));

    export_decl->export_name = create_export_name(export_name);
    export_decl->extern_desc = export_desc;
    if (!export_decl->export_name) {
        return false;
    }

    instance_type->count = 1;
    instance_type->instance_decls = instance_decls;
    instance_decls[0].tag = WASM_COMP_COMPONENT_DECL_INSTANCE_EXPORTDECL;
    instance_decls[0].decl.export_decl = export_decl;

    type_section->types[0].tag = WASM_COMP_INSTANCE_TYPE;
    type_section->types[0].type.instance_type = instance_type;
    return true;
}

static bool
init_component_type_entry(WASMComponentTypes *type_entry, const char *export_name,
                          WASMComponentExternDesc *export_desc)
{
    auto *component_type = (WASMComponentComponentType *)wasm_runtime_malloc(
        sizeof(WASMComponentComponentType));
    WASMComponentComponentDecl *component_decls = nullptr;
    WASMComponentInstDecl *instance_decl = nullptr;
    WASMComponentComponentDeclExport *export_decl = nullptr;

    if (!type_entry || (!!export_name != !!export_desc) || !component_type) {
        return false;
    }

    memset(type_entry, 0, sizeof(WASMComponentTypes));
    memset(component_type, 0, sizeof(WASMComponentComponentType));

    if (export_name) {
        component_decls = (WASMComponentComponentDecl *)wasm_runtime_malloc(
            sizeof(WASMComponentComponentDecl));
        instance_decl = (WASMComponentInstDecl *)wasm_runtime_malloc(
            sizeof(WASMComponentInstDecl));
        export_decl = (WASMComponentComponentDeclExport *)wasm_runtime_malloc(
            sizeof(WASMComponentComponentDeclExport));
        if (!component_decls || !instance_decl || !export_decl) {
            return false;
        }

        memset(component_decls, 0, sizeof(WASMComponentComponentDecl));
        memset(instance_decl, 0, sizeof(WASMComponentInstDecl));
        memset(export_decl, 0, sizeof(WASMComponentComponentDeclExport));
        export_decl->export_name = create_export_name(export_name);
        export_decl->extern_desc = export_desc;
        if (!export_decl->export_name) {
            return false;
        }

        component_type->count = 1;
        component_type->component_decls = component_decls;
        component_decls[0].tag = WASM_COMP_COMPONENT_DECL_EXPORT;
        component_decls[0].decl.instance_decl = instance_decl;
        instance_decl->tag = WASM_COMP_COMPONENT_DECL_INSTANCE_EXPORTDECL;
        instance_decl->decl.export_decl = export_decl;
    }

    type_entry->tag = WASM_COMP_COMPONENT_TYPE;
    type_entry->type.component_type = component_type;
    return true;
}

static bool
init_single_component_type_section(WASMComponentTypeSection *type_section,
                                   const char *export_name,
                                   WASMComponentExternDesc *export_desc)
{
    if (!type_section || (!!export_name != !!export_desc)) {
        return false;
    }

    memset(type_section, 0, sizeof(WASMComponentTypeSection));
    type_section->count = 1;
    type_section->types =
        (WASMComponentTypes *)wasm_runtime_malloc(sizeof(WASMComponentTypes));
    if (!type_section->types) {
        return false;
    }

    return init_component_type_entry(&type_section->types[0], export_name,
                                     export_desc);
}

static bool
append_component_type_to_type_section(WASMComponentTypeSection *type_section,
                                      const char *export_name,
                                      WASMComponentExternDesc *export_desc)
{
    auto *new_types = type_section
                          ? (WASMComponentTypes *)wasm_runtime_malloc(
                                sizeof(WASMComponentTypes)
                                * (type_section->count + 1))
                          : nullptr;

    if (!type_section || (!!export_name != !!export_desc) || !new_types) {
        return false;
    }

    memset(new_types, 0, sizeof(WASMComponentTypes) * (type_section->count + 1));
    memcpy(new_types, type_section->types,
           sizeof(WASMComponentTypes) * type_section->count);

    if (!init_component_type_entry(&new_types[type_section->count], export_name,
                                   export_desc)) {
        wasm_runtime_free(new_types);
        return false;
    }

    if (type_section->types) {
        wasm_runtime_free(type_section->types);
    }
    type_section->types = new_types;
    type_section->count++;
    return true;
}

static bool
append_instance_type_to_type_section(WASMComponentTypeSection *type_section,
                                     const char *export_name,
                                     WASMComponentExternDesc *export_desc)
{
    auto *instance_type =
        (WASMComponentInstType *)wasm_runtime_malloc(sizeof(WASMComponentInstType));
    auto *instance_decls = (WASMComponentInstDecl *)wasm_runtime_malloc(
        sizeof(WASMComponentInstDecl));
    auto *export_decl =
        (WASMComponentComponentDeclExport *)wasm_runtime_malloc(
            sizeof(WASMComponentComponentDeclExport));
    auto *new_types = type_section
                          ? (WASMComponentTypes *)wasm_runtime_malloc(
                                sizeof(WASMComponentTypes)
                                * (type_section->count + 1))
                          : nullptr;

    if (!type_section || !export_name || !export_desc || !instance_type
        || !instance_decls || !export_decl || !new_types) {
        return false;
    }

    memset(instance_type, 0, sizeof(WASMComponentInstType));
    memset(instance_decls, 0, sizeof(WASMComponentInstDecl));
    memset(export_decl, 0, sizeof(WASMComponentComponentDeclExport));
    memset(new_types, 0,
           sizeof(WASMComponentTypes) * (type_section->count + 1));
    memcpy(new_types, type_section->types,
           sizeof(WASMComponentTypes) * type_section->count);

    export_decl->export_name = create_export_name(export_name);
    export_decl->extern_desc = export_desc;
    if (!export_decl->export_name) {
        return false;
    }

    instance_type->count = 1;
    instance_type->instance_decls = instance_decls;
    instance_decls[0].tag = WASM_COMP_COMPONENT_DECL_INSTANCE_EXPORTDECL;
    instance_decls[0].decl.export_decl = export_decl;

    new_types[type_section->count].tag = WASM_COMP_INSTANCE_TYPE;
    new_types[type_section->count].type.instance_type = instance_type;

    if (type_section->types) {
        wasm_runtime_free(type_section->types);
    }
    type_section->types = new_types;
    type_section->count++;
    return true;
}

static bool
append_top_level_resource_type_section(WASMComponentModule *component_module)
{
    WASMComponent *component = &component_module->component;
    const uint32_t old_count = component->section_count;
    auto *new_sections = (WASMComponentSection *)wasm_runtime_malloc(
        sizeof(WASMComponentSection) * (old_count + 1));
    if (!new_sections) {
        return false;
    }

    memset(new_sections, 0, sizeof(WASMComponentSection) * (old_count + 1));
    memcpy(new_sections, component->sections,
           sizeof(WASMComponentSection) * old_count);
    wasm_runtime_free(component->sections);
    component->sections = new_sections;
    component->section_count = old_count + 1;

    auto *type_section = &component->sections[old_count];
    type_section->id = WASM_COMP_SECTION_TYPE;
    type_section->parsed.type_section =
        (WASMComponentTypeSection *)wasm_runtime_malloc(
            sizeof(WASMComponentTypeSection));
    if (!type_section->parsed.type_section) {
        return false;
    }
    memset(type_section->parsed.type_section, 0, sizeof(WASMComponentTypeSection));
    return init_resource_type_section(type_section->parsed.type_section, 1, false);
}

static bool
append_nested_resource_component_instance_sections(
    WASMComponentModule *component_module)
{
    WASMComponent *component = &component_module->component;
    uint32_t component_idx = 0;
    const uint32_t old_count = component->section_count;
    auto *new_sections = (WASMComponentSection *)wasm_runtime_malloc(
        sizeof(WASMComponentSection) * (old_count + 2));
    if (!new_sections) {
        return false;
    }

    for (uint32_t i = 0; i < old_count; i++) {
        if (component->sections[i].id == WASM_COMP_SECTION_COMPONENT) {
            component_idx++;
        }
    }

    memset(new_sections, 0, sizeof(WASMComponentSection) * (old_count + 2));
    memcpy(new_sections, component->sections,
           sizeof(WASMComponentSection) * old_count);
    wasm_runtime_free(component->sections);
    component->sections = new_sections;
    component->section_count = old_count + 2;

    auto *component_section = &component->sections[old_count];
    auto *instance_section = &component->sections[old_count + 1];

    component_section->id = WASM_COMP_SECTION_COMPONENT;
    component_section->parsed.component =
        (WASMComponent *)wasm_runtime_malloc(sizeof(WASMComponent));
    if (!component_section->parsed.component) {
        return false;
    }
    memset(component_section->parsed.component, 0, sizeof(WASMComponent));
    component_section->parsed.component->section_count = 1;
    component_section->parsed.component->sections =
        (WASMComponentSection *)wasm_runtime_malloc(sizeof(WASMComponentSection));
    if (!component_section->parsed.component->sections) {
        return false;
    }
    memset(component_section->parsed.component->sections, 0,
           sizeof(WASMComponentSection));
    component_section->parsed.component->sections[0].id = WASM_COMP_SECTION_TYPE;
    component_section->parsed.component->sections[0].parsed.type_section =
        (WASMComponentTypeSection *)wasm_runtime_malloc(
            sizeof(WASMComponentTypeSection));
    if (!component_section->parsed.component->sections[0].parsed.type_section) {
        return false;
    }
    memset(component_section->parsed.component->sections[0].parsed.type_section, 0,
           sizeof(WASMComponentTypeSection));
    if (!init_resource_type_section(
            component_section->parsed.component->sections[0].parsed.type_section, 1,
            false)) {
        return false;
    }

    instance_section->id = WASM_COMP_SECTION_INSTANCES;
    instance_section->parsed.instance_section =
        (WASMComponentInstSection *)wasm_runtime_malloc(
            sizeof(WASMComponentInstSection));
    if (!instance_section->parsed.instance_section) {
        return false;
    }
    memset(instance_section->parsed.instance_section, 0,
           sizeof(WASMComponentInstSection));
    instance_section->parsed.instance_section->count = 1;
    instance_section->parsed.instance_section->instances =
        (WASMComponentInst *)wasm_runtime_malloc(sizeof(WASMComponentInst));
    if (!instance_section->parsed.instance_section->instances) {
        return false;
    }
    memset(instance_section->parsed.instance_section->instances, 0,
           sizeof(WASMComponentInst));
    instance_section->parsed.instance_section->instances[0]
        .instance_expression_tag = WASM_COMP_INSTANCE_EXPRESSION_WITH_ARGS;
    instance_section->parsed.instance_section->instances[0]
        .expression.with_args.idx = component_idx;
    instance_section->parsed.instance_section->instances[0]
        .expression.with_args.arg_len = 0;
    instance_section->parsed.instance_section->instances[0]
        .expression.with_args.args = nullptr;
    return true;
}

static WASMComponent *
create_empty_component()
{
    auto *component = (WASMComponent *)wasm_runtime_malloc(sizeof(WASMComponent));
    if (!component) {
        return nullptr;
    }

    memset(component, 0, sizeof(WASMComponent));
    return component;
}

static const uint8_t runtime_value_section_i32_bytes[] = { 0x2a, 0x00, 0x00, 0x00 };
static const uint8_t runtime_value_section_i32_two_bytes[] = { 0x02 };
static const uint8_t runtime_value_section_i32_three_bytes[] = { 0x03 };
static const uint8_t runtime_value_section_i32_five_bytes[] = { 0x05 };

static wasm_component_value_t
make_component_string_value(const std::string &value)
{
    wasm_component_value_t result = {};
    uint8_t *storage = (uint8_t *)wasm_runtime_malloc((uint32_t)value.size() + 5);
    uint32_t len = (uint32_t)value.size();
    uint32_t leb_len = 0;

    EXPECT_NE(storage, nullptr);
    if (!storage) {
        return result;
    }

    result.type.kind = WASM_COMPONENT_VALUE_TYPE_PRIMITIVE;
    result.type.type.primitive_type = WASM_COMPONENT_PRIMITIVE_VALUE_STRING;
    do {
        uint8_t byte = (uint8_t)(len & 0x7F);
        len >>= 7;
        if (len != 0) {
            byte |= 0x80;
        }
        storage[leb_len++] = byte;
    } while (len != 0);

    memcpy(storage + leb_len, value.data(), value.size());
    result.storage_kind = WASM_COMPONENT_VALUE_STORAGE_OWNED;
    result.byte_size = leb_len + (uint32_t)value.size();
    result.storage.owned_data = storage;
    return result;
}

static wasm_component_value_t
make_component_s32_value(int32_t value)
{
    wasm_component_value_t result = {};
    uint8_t storage[5];
    uint32_t len = 0;
    int32_t current = value;
    bool done = false;

    result.type.kind = WASM_COMPONENT_VALUE_TYPE_PRIMITIVE;
    result.type.type.primitive_type = WASM_COMPONENT_PRIMITIVE_VALUE_S32;
    result.storage_kind = WASM_COMPONENT_VALUE_STORAGE_INLINE;

    while (!done) {
        uint8_t byte = (uint8_t)(current & 0x7f);
        current >>= 7;
        done = (current == 0 && (byte & 0x40) == 0)
               || (current == -1 && (byte & 0x40) != 0);
        if (!done) {
            byte |= 0x80;
        }
        storage[len++] = byte;
    }

    result.byte_size = len;
    memcpy(result.storage.inline_storage, storage, len);
    return result;
}

static wasm_component_value_t
make_component_defined_value(const void *data, uint32_t size)
{
    wasm_component_value_t result = {};

    result.type.kind = WASM_COMPONENT_VALUE_TYPE_DEFINED;
    result.byte_size = size;
    if (size == 0) {
        return result;
    }

    auto *storage = (uint8_t *)wasm_runtime_malloc(size);
    EXPECT_NE(storage, nullptr);
    if (!storage) {
        return result;
    }

    memcpy(storage, data, size);
    result.storage_kind = WASM_COMPONENT_VALUE_STORAGE_OWNED;
    result.storage.owned_data = storage;
    return result;
}

static wasm_component_value_t
make_component_defined_inline_value(const void *data, uint32_t size)
{
    wasm_component_value_t result = {};

    result.type.kind = WASM_COMPONENT_VALUE_TYPE_DEFINED;
    result.byte_size = size;
    if (size == 0) {
        return result;
    }

    EXPECT_LE(size, WASM_COMPONENT_VALUE_INLINE_STORAGE_SIZE);
    if (size > WASM_COMPONENT_VALUE_INLINE_STORAGE_SIZE || !data) {
        return result;
    }

    result.storage_kind = WASM_COMPONENT_VALUE_STORAGE_INLINE;
    memcpy(result.storage.inline_storage, data, size);
    return result;
}

static wasm_component_value_t
make_component_list_u8_value(const void *data, uint32_t size)
{
    return make_component_defined_value(data, size);
}

static wasm_module_inst_t
instantiate_component_with_default_wasi(wasm_module_t module,
                                        ComponentHelper *helper)
{
    struct InstantiationArgs2 *inst_args = nullptr;
    wasm_module_inst_t module_inst = nullptr;

    if (!wasm_runtime_instantiation_args_create(&inst_args)) {
        return nullptr;
    }

    wasm_runtime_instantiation_args_set_default_stack_size(inst_args,
                                                           helper->stack_size);
    wasm_runtime_instantiation_args_set_host_managed_heap_size(
        inst_args, helper->heap_size);
    wasm_runtime_instantiation_args_set_wasi_stdio(inst_args, 0, 1, 2);
    wasm_runtime_instantiation_args_set_wasi_dir(inst_args, nullptr, 0, nullptr,
                                                 0);

    module_inst = wasm_runtime_instantiate_ex2(
        module, inst_args, helper->error_buf,
        (uint32_t)sizeof(helper->error_buf));
    wasm_runtime_instantiation_args_destroy(inst_args);
    return module_inst;
}

static uint32_t
count_component_types(const WASMComponent *component)
{
    uint32_t count = 0;

    if (!component) {
        return 0;
    }

    for (uint32_t i = 0; i < component->section_count; i++) {
        if (component->sections[i].id == WASM_COMP_SECTION_TYPE
            && component->sections[i].parsed.type_section) {
            count += component->sections[i].parsed.type_section->count;
        }
    }

    return count;
}

static bool
decode_component_string_arg(const wasm_component_value_t *value, std::string *out)
{
    const auto *data = (const uint8_t *)wasm_component_value_get_data(value);
    uint32_t len = 0;
    uint32_t shift = 0;
    uint32_t offset = 0;

    if (!data || !value || value->byte_size == 0) {
        return false;
    }

    while (offset < value->byte_size) {
        const uint8_t byte = data[offset++];
        len |= (uint32_t)(byte & 0x7F) << shift;
        if ((byte & 0x80) == 0) {
            break;
        }
        shift += 7;
    }

    if (offset + len != value->byte_size) {
        return false;
    }

    out->assign((const char *)(data + offset), len);
    return true;
}

static bool
decode_component_s32_arg(const wasm_component_value_t *value, int32_t *out)
{
    const auto *data = (const uint8_t *)wasm_component_value_get_data(value);
    int32_t result = 0;
    uint32_t shift = 0;
    uint32_t offset = 0;
    uint8_t byte = 0;

    if (!value || !out || !data || value->byte_size == 0) {
        return false;
    }

    do {
        if (offset >= value->byte_size || shift >= 35) {
            return false;
        }
        byte = data[offset++];
        result |= (int32_t)(byte & 0x7F) << shift;
        shift += 7;
    } while (byte & 0x80);

    if (offset != value->byte_size) {
        return false;
    }

    if (shift < 32 && (byte & 0x40)) {
        result |= -((int32_t)1 << shift);
    }

    *out = result;
    return true;
}

struct HostScalarCallState {
    int call_count;
    int32_t last_a;
    int32_t last_b;
};

static bool
host_scalar_add_callback(wasm_module_inst_t caller_component_inst, void *user_data,
                         uint32_t num_results, wasm_component_value_t results[],
                         uint32_t num_args,
                         const wasm_component_value_t args[], char *error_buf,
                         uint32_t error_buf_size)
{
    auto *state = (HostScalarCallState *)user_data;
    const auto *arg0 = (const uint8_t *)wasm_component_value_get_data(&args[0]);
    const auto *arg1 = (const uint8_t *)wasm_component_value_get_data(&args[1]);

    if (!caller_component_inst || !state || num_args != 2 || num_results != 1
        || !arg0 || !arg1 || args[0].type.kind != WASM_COMPONENT_VALUE_TYPE_PRIMITIVE
        || args[1].type.kind != WASM_COMPONENT_VALUE_TYPE_PRIMITIVE
        || args[0].type.type.primitive_type != WASM_COMPONENT_PRIMITIVE_VALUE_S32
        || args[1].type.type.primitive_type != WASM_COMPONENT_PRIMITIVE_VALUE_S32) {
        snprintf(error_buf, error_buf_size, "unexpected scalar host callback ABI");
        return false;
    }

    state->call_count++;
    state->last_a = (int8_t)arg0[0];
    state->last_b = (int8_t)arg1[0];
    results[0] = make_component_s32_value(state->last_a + state->last_b);
    return true;
}

struct HostStringCallState {
    int call_count;
    std::string last_arg;
};

struct HostListU8CallState {
    int call_count;
    const void *last_arg_data;
    std::vector<uint8_t> last_arg;
    void *last_result_data;
    std::vector<uint8_t> next_result;
};

struct HostListU8ScalarResultCallState {
    int call_count;
    const void *last_arg_data;
    std::vector<uint8_t> last_arg;
    int32_t next_result;
};

struct HostCompositeCallState {
    int call_count;
    const void *last_arg_data;
    std::vector<uint8_t> expected_arg;
    int32_t result_value;
};

enum HostCompositeResultMode {
    HOST_COMPOSITE_RESULT_INLINE = 0,
    HOST_COMPOSITE_RESULT_OWNED,
    HOST_COMPOSITE_RESULT_PRIMITIVE,
    HOST_COMPOSITE_RESULT_MISSING_BYTES
};

struct HostCompositeResultCallState {
    int call_count;
    int32_t last_a;
    int32_t last_b;
    uint32_t missing_byte_size;
    HostCompositeResultMode mode;
    std::vector<uint8_t> next_result;
};

static bool
host_string_echo_callback(wasm_module_inst_t caller_component_inst, void *user_data,
                          uint32_t num_results, wasm_component_value_t results[],
                          uint32_t num_args,
                          const wasm_component_value_t args[], char *error_buf,
                          uint32_t error_buf_size)
{
    auto *state = (HostStringCallState *)user_data;
    std::string decoded;

    if (!caller_component_inst || !state || num_args != 1 || num_results != 1
        || args[0].type.kind != WASM_COMPONENT_VALUE_TYPE_PRIMITIVE
        || args[0].type.type.primitive_type
               != WASM_COMPONENT_PRIMITIVE_VALUE_STRING
        || !decode_component_string_arg(&args[0], &decoded)) {
        snprintf(error_buf, error_buf_size, "unexpected string host callback ABI");
        return false;
    }

    state->call_count++;
    state->last_arg = decoded;
    results[0] = make_component_string_value(decoded + "!");
    return true;
}

static bool
host_invalid_string_result_callback(wasm_module_inst_t caller_component_inst,
                                    void *user_data, uint32_t num_results,
                                    wasm_component_value_t results[],
                                    uint32_t num_args,
                                    const wasm_component_value_t args[],
                                    char *error_buf, uint32_t error_buf_size)
{
    (void)caller_component_inst;
    (void)user_data;
    (void)num_args;
    (void)args;
    (void)error_buf;
    (void)error_buf_size;

    if (num_results != 1) {
        return false;
    }

    results[0].type.kind = WASM_COMPONENT_VALUE_TYPE_PRIMITIVE;
    results[0].type.type.primitive_type = WASM_COMPONENT_PRIMITIVE_VALUE_STRING;
    results[0].storage_kind = WASM_COMPONENT_VALUE_STORAGE_INLINE;
    results[0].byte_size = 2;
    results[0].storage.inline_storage[0] = 0x01;
    results[0].storage.inline_storage[1] = 0xFF;
    return true;
}

static bool
host_list_u8_echo_callback(wasm_module_inst_t caller_component_inst,
                           void *user_data, uint32_t num_results,
                           wasm_component_value_t results[], uint32_t num_args,
                           const wasm_component_value_t args[], char *error_buf,
                           uint32_t error_buf_size)
{
    auto *state = (HostListU8CallState *)user_data;
    const auto *arg_data = (const uint8_t *)wasm_component_value_get_data(&args[0]);

    if (!caller_component_inst || !state || num_args != 1 || num_results != 1
        || args[0].type.kind != WASM_COMPONENT_VALUE_TYPE_DEFINED
        || (args[0].byte_size > 0 && !arg_data)) {
        snprintf(error_buf, error_buf_size, "unexpected list<scalar> host callback ABI");
        return false;
    }

    state->call_count++;
    state->last_arg_data = arg_data;
    state->last_arg.assign(arg_data, arg_data + args[0].byte_size);
    state->last_result_data = nullptr;

    results[0].type.kind = WASM_COMPONENT_VALUE_TYPE_DEFINED;
    results[0].byte_size = (uint32_t)state->next_result.size();
    if (state->next_result.empty()) {
        return true;
    }

    auto *storage =
        (uint8_t *)wasm_runtime_malloc((uint32_t)state->next_result.size());
    if (!storage) {
        snprintf(error_buf, error_buf_size, "allocate list<scalar> result failed");
        return false;
    }

    memcpy(storage, state->next_result.data(), state->next_result.size());
    results[0].storage_kind = WASM_COMPONENT_VALUE_STORAGE_OWNED;
    results[0].storage.owned_data = storage;
    state->last_result_data = storage;
    return true;
}

static bool
host_list_scalar_result_only_callback(wasm_module_inst_t caller_component_inst,
                                      void *user_data, uint32_t num_results,
                                      wasm_component_value_t results[],
                                      uint32_t num_args,
                                      const wasm_component_value_t args[],
                                      char *error_buf,
                                      uint32_t error_buf_size)
{
    auto *state = (HostListU8CallState *)user_data;

    (void)args;
    if (!caller_component_inst || !state || num_args != 0 || num_results != 1) {
        snprintf(error_buf, error_buf_size,
                 "unexpected list<scalar>-result-only host callback ABI");
        return false;
    }

    state->call_count++;
    state->last_arg_data = nullptr;
    state->last_arg.clear();
    state->last_result_data = nullptr;
    results[0].type.kind = WASM_COMPONENT_VALUE_TYPE_DEFINED;
    results[0].byte_size = (uint32_t)state->next_result.size();
    if (state->next_result.empty()) {
        return true;
    }

    auto *storage =
        (uint8_t *)wasm_runtime_malloc((uint32_t)state->next_result.size());
    if (!storage) {
        snprintf(error_buf, error_buf_size, "allocate list<scalar> result failed");
        return false;
    }

    memcpy(storage, state->next_result.data(), state->next_result.size());
    results[0].storage_kind = WASM_COMPONENT_VALUE_STORAGE_OWNED;
    results[0].storage.owned_data = storage;
    state->last_result_data = storage;
    return true;
}

static bool
host_invalid_list_u8_result_callback(wasm_module_inst_t caller_component_inst,
                                     void *user_data, uint32_t num_results,
                                     wasm_component_value_t results[],
                                     uint32_t num_args,
                                     const wasm_component_value_t args[],
                                     char *error_buf, uint32_t error_buf_size)
{
    (void)caller_component_inst;
    (void)user_data;
    (void)num_args;
    (void)args;
    (void)error_buf;
    (void)error_buf_size;

    if (num_results != 1) {
        return false;
    }

    results[0].type.kind = WASM_COMPONENT_VALUE_TYPE_DEFINED;
    results[0].byte_size = 4;
    return true;
}

static bool
host_list_u8_scalar_result_callback(wasm_module_inst_t caller_component_inst,
                                    void *user_data, uint32_t num_results,
                                    wasm_component_value_t results[],
                                    uint32_t num_args,
                                    const wasm_component_value_t args[],
                                    char *error_buf,
                                    uint32_t error_buf_size)
{
    auto *state = (HostListU8ScalarResultCallState *)user_data;
    const auto *arg_data = (const uint8_t *)wasm_component_value_get_data(&args[0]);

    if (!caller_component_inst || !state || num_args != 1 || num_results != 1
        || args[0].type.kind != WASM_COMPONENT_VALUE_TYPE_DEFINED
        || (args[0].byte_size > 0 && !arg_data)) {
        snprintf(error_buf, error_buf_size,
                 "unexpected list<scalar>-scalar host callback ABI");
        return false;
    }

    state->call_count++;
    state->last_arg_data = arg_data;
    state->last_arg.assign(arg_data, arg_data + args[0].byte_size);
    results[0] = make_component_s32_value(state->next_result);
    return true;
}

static bool
host_composite_param_callback(wasm_module_inst_t caller_component_inst,
                              void *user_data, uint32_t num_results,
                              wasm_component_value_t results[],
                              uint32_t num_args,
                              const wasm_component_value_t args[],
                              char *error_buf, uint32_t error_buf_size)
{
    auto *state = (HostCompositeCallState *)user_data;
    const auto *arg_data = (const uint8_t *)wasm_component_value_get_data(&args[0]);

    if (!caller_component_inst || !state || num_args != 1 || num_results != 1
        || args[0].type.kind != WASM_COMPONENT_VALUE_TYPE_DEFINED
        || args[0].byte_size != state->expected_arg.size()
        || (args[0].byte_size > 0 && !arg_data)
        || (args[0].byte_size > 0
            && memcmp(arg_data, state->expected_arg.data(), args[0].byte_size))) {
        snprintf(error_buf, error_buf_size,
                 "unexpected composite host callback ABI");
        return false;
    }

    state->call_count++;
    state->last_arg_data = arg_data;
    results[0] = make_component_s32_value(state->result_value);
    return true;
}

static bool
host_composite_result_callback(wasm_module_inst_t caller_component_inst,
                               void *user_data, uint32_t num_results,
                               wasm_component_value_t results[],
                               uint32_t num_args,
                               const wasm_component_value_t args[],
                               char *error_buf, uint32_t error_buf_size)
{
    auto *state = (HostCompositeResultCallState *)user_data;
    const auto *arg0 = (const uint8_t *)wasm_component_value_get_data(&args[0]);
    const auto *arg1 = (const uint8_t *)wasm_component_value_get_data(&args[1]);

    if (!caller_component_inst || !state || num_args != 2 || num_results != 1
        || !arg0 || !arg1 || args[0].type.kind != WASM_COMPONENT_VALUE_TYPE_PRIMITIVE
        || args[1].type.kind != WASM_COMPONENT_VALUE_TYPE_PRIMITIVE
        || args[0].type.type.primitive_type != WASM_COMPONENT_PRIMITIVE_VALUE_S32
        || args[1].type.type.primitive_type != WASM_COMPONENT_PRIMITIVE_VALUE_S32) {
        snprintf(error_buf, error_buf_size,
                 "unexpected composite result host callback ABI");
        return false;
    }

    state->call_count++;
    state->last_a = (int8_t)arg0[0];
    state->last_b = (int8_t)arg1[0];

    switch (state->mode) {
        case HOST_COMPOSITE_RESULT_INLINE:
            results[0] = make_component_defined_inline_value(
                state->next_result.data(), (uint32_t)state->next_result.size());
            return true;
        case HOST_COMPOSITE_RESULT_OWNED:
            results[0] = make_component_defined_value(
                state->next_result.data(), (uint32_t)state->next_result.size());
            return true;
        case HOST_COMPOSITE_RESULT_PRIMITIVE:
            results[0] = make_component_s32_value(state->last_a + state->last_b);
            return true;
        case HOST_COMPOSITE_RESULT_MISSING_BYTES:
            results[0].type.kind = WASM_COMPONENT_VALUE_TYPE_DEFINED;
            results[0].byte_size = state->missing_byte_size;
            return true;
        default:
            snprintf(error_buf, error_buf_size,
                     "unexpected composite result host callback mode");
            return false;
    }
}

struct RuntimeValueFinalizerState {
    uint32_t call_count;
};

static void
runtime_value_test_finalizer(void *data, void *ctx)
{
    auto *state = (RuntimeValueFinalizerState *)ctx;
    if (state) {
        state->call_count++;
    }
    wasm_runtime_free(data);
}

static void
resource_handle_test_finalizer(void *data, void *ctx)
{
    auto *state = (RuntimeValueFinalizerState *)ctx;
    if (state) {
        state->call_count++;
    }
    wasm_runtime_free(data);
}

static bool
init_scalar_value_section_with_bytes(WASMComponentValueSection *value_section,
                                     const uint8_t *bytes, uint32_t byte_len)
{
    if (!value_section) {
        return false;
    }

    value_section->count = 1;
    value_section->values =
        (WASMComponentValue *)wasm_runtime_malloc(sizeof(WASMComponentValue));
    if (!value_section->values) {
        return false;
    }

    memset(value_section->values, 0, sizeof(WASMComponentValue));
    value_section->values[0].val_type = (WASMComponentValueType *)wasm_runtime_malloc(
        sizeof(WASMComponentValueType));
    if (!value_section->values[0].val_type) {
        return false;
    }

    value_section->values[0].val_type->type = WASM_COMP_VAL_TYPE_PRIMVAL;
    value_section->values[0].val_type->type_specific.primval_type =
        WASM_COMP_PRIMVAL_S32;
    value_section->values[0].core_data_len = byte_len;
    value_section->values[0].core_data = bytes;
    return true;
}

static bool
init_scalar_value_section(WASMComponentValueSection *value_section)
{
    return init_scalar_value_section_with_bytes(
        value_section, runtime_value_section_i32_bytes,
        (uint32_t)sizeof(runtime_value_section_i32_bytes));
}

static bool
init_value_section_with_type_and_bytes(WASMComponentValueSection *value_section,
                                       const WASMComponentValueType &value_type,
                                       const uint8_t *bytes, uint32_t byte_len)
{
    if (!value_section) {
        return false;
    }

    value_section->count = 1;
    value_section->values =
        (WASMComponentValue *)wasm_runtime_malloc(sizeof(WASMComponentValue));
    if (!value_section->values) {
        return false;
    }

    memset(value_section->values, 0, sizeof(WASMComponentValue));
    value_section->values[0].val_type = (WASMComponentValueType *)wasm_runtime_malloc(
        sizeof(WASMComponentValueType));
    if (!value_section->values[0].val_type) {
        return false;
    }

    *value_section->values[0].val_type = value_type;
    value_section->values[0].core_data_len = byte_len;
    value_section->values[0].core_data = bytes;
    return true;
}

static uint32_t
count_top_level_sort_entries(const WASMComponent *component, uint8_t sort)
{
    uint32_t count = 0;

    if (!component) {
        return 0;
    }

    for (uint32_t i = 0; i < component->section_count; i++) {
        const WASMComponentSection *section = &component->sections[i];

        switch (section->id) {
            case WASM_COMP_SECTION_IMPORTS:
                for (uint32_t j = 0; j < section->parsed.import_section->count; j++) {
                    const WASMComponentImport *component_import =
                        &section->parsed.import_section->imports[j];
                    if (!component_import->extern_desc) {
                        continue;
                    }
                    if ((sort == WASM_COMP_SORT_FUNC
                         && component_import->extern_desc->type
                                == WASM_COMP_EXTERN_FUNC)
                        || (sort == WASM_COMP_SORT_VALUE
                            && component_import->extern_desc->type
                                   == WASM_COMP_EXTERN_VALUE)
                        || (sort == WASM_COMP_SORT_INSTANCE
                            && component_import->extern_desc->type
                                   == WASM_COMP_EXTERN_INSTANCE)
                        || (sort == WASM_COMP_SORT_COMPONENT
                            && component_import->extern_desc->type
                                   == WASM_COMP_EXTERN_COMPONENT)) {
                        count++;
                    }
                }
                break;
            case WASM_COMP_SECTION_ALIASES:
                for (uint32_t j = 0; j < section->parsed.alias_section->count; j++) {
                    const WASMComponentAliasDefinition *alias_def =
                        &section->parsed.alias_section->aliases[j];
                    if (alias_def->alias_target_type == WASM_COMP_ALIAS_TARGET_EXPORT
                        && alias_def->sort && alias_def->sort->sort == sort) {
                        count++;
                    }
                }
                break;
            case WASM_COMP_SECTION_COMPONENT:
                if (sort == WASM_COMP_SORT_COMPONENT) {
                    count++;
                }
                break;
            case WASM_COMP_SECTION_INSTANCES:
                if (sort == WASM_COMP_SORT_INSTANCE) {
                    count += section->parsed.instance_section->count;
                }
                break;
            case WASM_COMP_SECTION_CANONS:
                if (sort == WASM_COMP_SORT_FUNC) {
                    for (uint32_t j = 0; j < section->parsed.canon_section->count;
                         j++) {
                        if (section->parsed.canon_section->canons[j].tag
                            == WASM_COMP_CANON_LIFT) {
                            count++;
                        }
                    }
                }
                break;
            case WASM_COMP_SECTION_VALUES:
                if (sort == WASM_COMP_SORT_VALUE) {
                    count += section->parsed.value_section->count;
                }
                break;
            default:
                break;
        }
    }

    return count;
}

static WASMComponentSection *
find_component_section(WASMComponentModule *component_module,
                       WASMComponentSectionType section_type)
{
    WASMComponent *component = &component_module->component;

    for (uint32_t i = 0; i < component->section_count; i++) {
        if (component->sections[i].id == section_type) {
            return &component->sections[i];
        }
    }

    return nullptr;
}

static uint32_t
count_top_level_core_func_entries(const WASMComponent *component)
{
    uint32_t count = 0;

    if (!component) {
        return 0;
    }

    for (uint32_t i = 0; i < component->section_count; i++) {
        const WASMComponentSection *section = &component->sections[i];

        switch (section->id) {
            case WASM_COMP_SECTION_ALIASES:
                for (uint32_t j = 0; j < section->parsed.alias_section->count; j++) {
                    const WASMComponentAliasDefinition *alias_def =
                        &section->parsed.alias_section->aliases[j];
                    if (alias_def->alias_target_type
                            == WASM_COMP_ALIAS_TARGET_CORE_EXPORT
                        && alias_def->sort
                        && alias_def->sort->sort == WASM_COMP_SORT_CORE_SORT
                        && alias_def->sort->core_sort
                               == WASM_COMP_CORE_SORT_FUNC) {
                        count++;
                    }
                }
                break;
            case WASM_COMP_SECTION_CANONS:
                for (uint32_t j = 0; j < section->parsed.canon_section->count; j++) {
                    switch (section->parsed.canon_section->canons[j].tag) {
                        case WASM_COMP_CANON_LOWER:
                        case WASM_COMP_CANON_RESOURCE_NEW:
                        case WASM_COMP_CANON_RESOURCE_DROP:
                        case WASM_COMP_CANON_RESOURCE_DROP_ASYNC:
                        case WASM_COMP_CANON_RESOURCE_REP:
                            count++;
                            break;
                        default:
                            break;
                    }
                }
                break;
            default:
                break;
        }
    }

    return count;
}

static uint32_t
count_top_level_core_module_entries(const WASMComponent *component)
{
    uint32_t count = 0;

    if (!component) {
        return 0;
    }

    for (uint32_t i = 0; i < component->section_count; i++) {
        if (component->sections[i].id == WASM_COMP_SECTION_CORE_MODULE) {
            count++;
        }
    }

    return count;
}

static uint32_t
count_top_level_core_instance_entries(const WASMComponent *component)
{
    uint32_t count = 0;

    if (!component) {
        return 0;
    }

    for (uint32_t i = 0; i < component->section_count; i++) {
        if (component->sections[i].id == WASM_COMP_SECTION_CORE_INSTANCE) {
            count += component->sections[i].parsed.core_instance_section->count;
        }
    }

    return count;
}

static WASMComponentCanon *
find_first_canon_lift(WASMComponentModule *component_module)
{
    auto *section =
        find_component_section(component_module, WASM_COMP_SECTION_CANONS);
    if (!section || !section->parsed.canon_section) {
        return nullptr;
    }

    for (uint32_t i = 0; i < section->parsed.canon_section->count; i++) {
        if (section->parsed.canon_section->canons[i].tag == WASM_COMP_CANON_LIFT) {
            return &section->parsed.canon_section->canons[i];
        }
    }

    return nullptr;
}

static WASMComponentCanon *
find_first_canon_lower(WASMComponentModule *component_module)
{
    WASMComponent *component = &component_module->component;

    for (uint32_t section_idx = 0; section_idx < component->section_count;
         section_idx++) {
        auto *section = &component->sections[section_idx];
        if (section->id != WASM_COMP_SECTION_CANONS
            || !section->parsed.canon_section) {
            continue;
        }

        for (uint32_t i = 0; i < section->parsed.canon_section->count; i++) {
            if (section->parsed.canon_section->canons[i].tag
                == WASM_COMP_CANON_LOWER) {
                return &section->parsed.canon_section->canons[i];
            }
        }
    }

    return nullptr;
}

static WASMComponentFuncType *
lookup_local_component_func_type(WASMComponentModule *component_module,
                                 uint32_t type_idx)
{
    WASMComponent *component = &component_module->component;

    for (uint32_t i = 0; i < component->section_count; i++) {
        WASMComponentSection *section = &component->sections[i];

        if (section->id != WASM_COMP_SECTION_TYPE || !section->parsed.type_section) {
            continue;
        }

        if (type_idx < section->parsed.type_section->count) {
            WASMComponentTypes *type_entry =
                &section->parsed.type_section->types[type_idx];
            return type_entry->tag == WASM_COMP_FUNC_TYPE
                       ? type_entry->type.func_type
                       : nullptr;
        }

        type_idx -= section->parsed.type_section->count;
    }

    return nullptr;
}

static int32_t
find_top_level_export_sort_index(WASMComponentModule *component_module,
                                 const char *export_name, uint8_t sort)
{
    WASMComponent *component = &component_module->component;

    for (uint32_t section_idx = 0; section_idx < component->section_count;
         section_idx++) {
        auto *section = &component->sections[section_idx];
        if (section->id != WASM_COMP_SECTION_EXPORTS
            || !section->parsed.export_section) {
            continue;
        }

        for (uint32_t i = 0; i < section->parsed.export_section->count; i++) {
            auto *component_export = &section->parsed.export_section->exports[i];
            if (!component_export->export_name || !component_export->sort_idx
                || !component_export->sort_idx->sort) {
                continue;
            }

            const char *name = component_export->export_name->tag
                                       == WASM_COMP_IMPORTNAME_SIMPLE
                                   ? component_export->export_name->exported.simple.name
                                         ->name
                                   : nullptr;
            if (name && !strcmp(name, export_name)
                && component_export->sort_idx->sort->sort == sort) {
                return (int32_t)component_export->sort_idx->idx;
            }
        }
    }

    return -1;
}

static const WASMComponentCanon *
lookup_top_level_canon_by_func_index(WASMComponentModule *component_module,
                                     uint32_t func_idx)
{
    WASMComponent *component = &component_module->component;

    for (uint32_t i = 0; i < component->section_count; i++) {
        auto *section = &component->sections[i];
        if (section->id != WASM_COMP_SECTION_CANONS || !section->parsed.canon_section) {
            continue;
        }

        for (uint32_t j = 0; j < section->parsed.canon_section->count; j++) {
            if (section->parsed.canon_section->canons[j].tag
                != WASM_COMP_CANON_LIFT) {
                continue;
            }

            if (func_idx == 0) {
                return &section->parsed.canon_section->canons[j];
            }

            func_idx--;
        }
    }

    return nullptr;
}

static WASMComponentFuncType *
lookup_top_level_exported_canon_func_type(WASMComponentModule *component_module,
                                          const char *export_name)
{
    const int32_t func_idx = find_top_level_export_sort_index(
        component_module, export_name, WASM_COMP_SORT_FUNC);
    const WASMComponentCanon *canon =
        func_idx >= 0
            ? lookup_top_level_canon_by_func_index(component_module,
                                                   (uint32_t)func_idx)
            : nullptr;

    if (!canon || canon->tag != WASM_COMP_CANON_LIFT) {
        return nullptr;
    }

    return lookup_local_component_func_type(component_module,
                                            canon->canon_data.lift.type_idx);
}

static int32_t
lookup_top_level_exported_canon_func_type_idx(WASMComponentModule *component_module,
                                              const char *export_name)
{
    const int32_t func_idx = find_top_level_export_sort_index(
        component_module, export_name, WASM_COMP_SORT_FUNC);
    const WASMComponentCanon *canon =
        func_idx >= 0
            ? lookup_top_level_canon_by_func_index(component_module,
                                                   (uint32_t)func_idx)
            : nullptr;

    if (!canon || canon->tag != WASM_COMP_CANON_LIFT) {
        return -1;
    }

    return (int32_t)canon->canon_data.lift.type_idx;
}

static WASMComponentCanon *
lookup_top_level_exported_canon(WASMComponentModule *component_module,
                                const char *export_name)
{
    const int32_t func_idx = find_top_level_export_sort_index(
        component_module, export_name, WASM_COMP_SORT_FUNC);

    return func_idx >= 0
               ? (WASMComponentCanon *)lookup_top_level_canon_by_func_index(
                     component_module, (uint32_t)func_idx)
               : nullptr;
}

static bool
append_top_level_canon_lower_relift_export_sections_for_func(
    WASMComponentModule *component_module, uint32_t source_func_idx,
    uint32_t lift_type_idx, const char *top_export_name)
{
    WASMComponent *component = &component_module->component;
    const uint32_t new_core_func_idx = count_top_level_core_func_entries(component);
    const uint32_t new_func_idx =
        count_top_level_sort_entries(component, WASM_COMP_SORT_FUNC);
    const uint32_t old_count = component->section_count;
    auto *new_sections = (WASMComponentSection *)wasm_runtime_malloc(
        sizeof(WASMComponentSection) * (old_count + 2));

    if (!new_sections) {
        return false;
    }

    memset(new_sections, 0, sizeof(WASMComponentSection) * (old_count + 2));
    memcpy(new_sections, component->sections,
           sizeof(WASMComponentSection) * old_count);
    wasm_runtime_free(component->sections);
    component->sections = new_sections;
    component->section_count = old_count + 2;

    auto *canon_section = &component->sections[old_count];
    auto *export_section = &component->sections[old_count + 1];

    canon_section->id = WASM_COMP_SECTION_CANONS;
    canon_section->parsed.canon_section =
        (WASMComponentCanonSection *)wasm_runtime_malloc(
            sizeof(WASMComponentCanonSection));
    if (!canon_section->parsed.canon_section) {
        return false;
    }
    memset(canon_section->parsed.canon_section, 0, sizeof(WASMComponentCanonSection));
    canon_section->parsed.canon_section->count = 2;
    canon_section->parsed.canon_section->canons =
        (WASMComponentCanon *)wasm_runtime_malloc(sizeof(WASMComponentCanon) * 2);
    if (!canon_section->parsed.canon_section->canons) {
        return false;
    }
    memset(canon_section->parsed.canon_section->canons, 0,
           sizeof(WASMComponentCanon) * 2);
    canon_section->parsed.canon_section->canons[0].tag = WASM_COMP_CANON_LOWER;
    canon_section->parsed.canon_section->canons[0].canon_data.lower.func_idx =
        source_func_idx;
    canon_section->parsed.canon_section->canons[1].tag = WASM_COMP_CANON_LIFT;
    canon_section->parsed.canon_section->canons[1].canon_data.lift.core_func_idx =
        new_core_func_idx;
    canon_section->parsed.canon_section->canons[1].canon_data.lift.type_idx =
        lift_type_idx;

    export_section->id = WASM_COMP_SECTION_EXPORTS;
    export_section->parsed.export_section =
        (WASMComponentExportSection *)wasm_runtime_malloc(
            sizeof(WASMComponentExportSection));
    if (!export_section->parsed.export_section) {
        return false;
    }
    memset(export_section->parsed.export_section, 0,
           sizeof(WASMComponentExportSection));
    export_section->parsed.export_section->count = 1;
    export_section->parsed.export_section->exports =
        (WASMComponentExport *)wasm_runtime_malloc(sizeof(WASMComponentExport));
    if (!export_section->parsed.export_section->exports) {
        return false;
    }
    memset(export_section->parsed.export_section->exports, 0,
           sizeof(WASMComponentExport));
    export_section->parsed.export_section->exports[0].export_name =
        create_export_name(top_export_name);
    export_section->parsed.export_section->exports[0].sort_idx =
        create_sort_idx(WASM_COMP_SORT_FUNC, new_func_idx);

    return export_section->parsed.export_section->exports[0].export_name
           && export_section->parsed.export_section->exports[0].sort_idx;
}

static bool
append_top_level_canon_lower_relift_export_sections(
    WASMComponentModule *component_module, const char *top_export_name)
{
    WASMComponentCanon *source_lift = find_first_canon_lift(component_module);

    return source_lift
           && append_top_level_canon_lower_relift_export_sections_for_func(
                component_module, 0, source_lift->canon_data.lift.type_idx,
                top_export_name);
}

static bool
append_top_level_lowered_core_caller_sections_for_func(
    WASMComponentModule *component_module, uint32_t source_func_idx,
    const char *core_module_path, const char *core_import_name)
{
    WASMComponent *component = &component_module->component;
    char error_buf[128] = {};
    const uint32_t new_core_func_idx = count_top_level_core_func_entries(component);
    const uint32_t new_core_module_idx =
        count_top_level_core_module_entries(component);
    const uint32_t old_count = component->section_count;
    auto *new_sections = (WASMComponentSection *)wasm_runtime_malloc(
        sizeof(WASMComponentSection) * (old_count + 3));

    if (!new_sections) {
        return false;
    }

    memset(new_sections, 0, sizeof(WASMComponentSection) * (old_count + 3));
    memcpy(new_sections, component->sections,
           sizeof(WASMComponentSection) * old_count);
    wasm_runtime_free(component->sections);
    component->sections = new_sections;
    component->section_count = old_count + 3;

    auto *canon_section = &component->sections[old_count];
    auto *core_module_section = &component->sections[old_count + 1];
    auto *core_instance_section = &component->sections[old_count + 2];

    canon_section->id = WASM_COMP_SECTION_CANONS;
    canon_section->parsed.canon_section =
        (WASMComponentCanonSection *)wasm_runtime_malloc(
            sizeof(WASMComponentCanonSection));
    if (!canon_section->parsed.canon_section) {
        return false;
    }
    memset(canon_section->parsed.canon_section, 0,
           sizeof(WASMComponentCanonSection));
    canon_section->parsed.canon_section->count = 1;
    canon_section->parsed.canon_section->canons =
        (WASMComponentCanon *)wasm_runtime_malloc(sizeof(WASMComponentCanon));
    if (!canon_section->parsed.canon_section->canons) {
        return false;
    }
    memset(canon_section->parsed.canon_section->canons, 0,
           sizeof(WASMComponentCanon));
    canon_section->parsed.canon_section->canons[0].tag = WASM_COMP_CANON_LOWER;
    canon_section->parsed.canon_section->canons[0].canon_data.lower.func_idx =
        source_func_idx;

    core_module_section->id = WASM_COMP_SECTION_CORE_MODULE;
    core_module_section->parsed.core_module = create_core_module_wrapper_from_file(
        core_module_path, "lowered-core-caller", error_buf,
        (uint32_t)sizeof(error_buf));
    if (!core_module_section->parsed.core_module) {
        return false;
    }

    core_instance_section->id = WASM_COMP_SECTION_CORE_INSTANCE;
    core_instance_section->parsed.core_instance_section =
        (WASMComponentCoreInstSection *)wasm_runtime_malloc(
            sizeof(WASMComponentCoreInstSection));
    if (!core_instance_section->parsed.core_instance_section) {
        return false;
    }
    memset(core_instance_section->parsed.core_instance_section, 0,
           sizeof(WASMComponentCoreInstSection));
    core_instance_section->parsed.core_instance_section->count = 1;
    core_instance_section->parsed.core_instance_section->instances =
        (WASMComponentCoreInst *)wasm_runtime_malloc(sizeof(WASMComponentCoreInst));
    if (!core_instance_section->parsed.core_instance_section->instances) {
        return false;
    }
    memset(core_instance_section->parsed.core_instance_section->instances, 0,
           sizeof(WASMComponentCoreInst));
    core_instance_section->parsed.core_instance_section->instances[0]
        .instance_expression_tag = WASM_COMP_INSTANCE_EXPRESSION_WITH_ARGS;
    core_instance_section->parsed.core_instance_section->instances[0]
        .expression.with_args.idx = new_core_module_idx;
    core_instance_section->parsed.core_instance_section->instances[0]
        .expression.with_args.arg_len = 1;
    core_instance_section->parsed.core_instance_section->instances[0]
        .expression.with_args.args =
        (WASMComponentInstArg *)wasm_runtime_malloc(sizeof(WASMComponentInstArg));
    if (!core_instance_section->parsed.core_instance_section->instances[0]
             .expression.with_args.args) {
        return false;
    }
    memset(core_instance_section->parsed.core_instance_section->instances[0]
               .expression.with_args.args,
           0, sizeof(WASMComponentInstArg));
    core_instance_section->parsed.core_instance_section->instances[0]
        .expression.with_args.args[0]
        .name = clone_core_name(core_import_name);
    core_instance_section->parsed.core_instance_section->instances[0]
        .expression.with_args.args[0]
        .idx.sort_idx = create_core_sort_idx(WASM_COMP_CORE_SORT_FUNC,
                                             new_core_func_idx);

    return core_instance_section->parsed.core_instance_section->instances[0]
               .expression.with_args.args[0]
               .name
           && core_instance_section->parsed.core_instance_section->instances[0]
                  .expression.with_args.args[0]
                  .idx.sort_idx;
}

static bool
append_top_level_core_export_lift_sections(WASMComponentModule *component_module,
                                           uint32_t core_instance_idx,
                                           const char *core_export_name,
                                           uint32_t lift_type_idx,
                                           const char *component_export_name)
{
    WASMComponent *component = &component_module->component;
    const uint32_t aliased_core_func_idx = count_top_level_core_func_entries(component);
    const uint32_t lifted_func_idx =
        count_top_level_sort_entries(component, WASM_COMP_SORT_FUNC);
    const uint32_t old_count = component->section_count;
    auto *new_sections = (WASMComponentSection *)wasm_runtime_malloc(
        sizeof(WASMComponentSection) * (old_count + 3));

    if (!new_sections) {
        return false;
    }

    memset(new_sections, 0, sizeof(WASMComponentSection) * (old_count + 3));
    memcpy(new_sections, component->sections,
           sizeof(WASMComponentSection) * old_count);
    wasm_runtime_free(component->sections);
    component->sections = new_sections;
    component->section_count = old_count + 3;

    auto *alias_section = &component->sections[old_count];
    auto *canon_section = &component->sections[old_count + 1];
    auto *export_section = &component->sections[old_count + 2];

    alias_section->id = WASM_COMP_SECTION_ALIASES;
    alias_section->parsed.alias_section =
        (WASMComponentAliasSection *)wasm_runtime_malloc(
            sizeof(WASMComponentAliasSection));
    if (!alias_section->parsed.alias_section) {
        return false;
    }
    memset(alias_section->parsed.alias_section, 0,
           sizeof(WASMComponentAliasSection));
    alias_section->parsed.alias_section->count = 1;
    alias_section->parsed.alias_section->aliases =
        (WASMComponentAliasDefinition *)wasm_runtime_malloc(
            sizeof(WASMComponentAliasDefinition));
    if (!alias_section->parsed.alias_section->aliases) {
        return false;
    }
    memset(alias_section->parsed.alias_section->aliases, 0,
           sizeof(WASMComponentAliasDefinition));
    alias_section->parsed.alias_section->aliases[0].sort =
        create_sort(WASM_COMP_SORT_CORE_SORT);
    if (!alias_section->parsed.alias_section->aliases[0].sort) {
        return false;
    }
    alias_section->parsed.alias_section->aliases[0].sort->core_sort =
        WASM_COMP_CORE_SORT_FUNC;
    alias_section->parsed.alias_section->aliases[0].alias_target_type =
        WASM_COMP_ALIAS_TARGET_CORE_EXPORT;
    alias_section->parsed.alias_section->aliases[0]
        .target.core_exported.instance_idx = core_instance_idx;
    alias_section->parsed.alias_section->aliases[0].target.core_exported.name =
        clone_core_name(core_export_name);
    if (!alias_section->parsed.alias_section->aliases[0]
             .target.core_exported.name) {
        return false;
    }

    canon_section->id = WASM_COMP_SECTION_CANONS;
    canon_section->parsed.canon_section =
        (WASMComponentCanonSection *)wasm_runtime_malloc(
            sizeof(WASMComponentCanonSection));
    if (!canon_section->parsed.canon_section) {
        return false;
    }
    memset(canon_section->parsed.canon_section, 0,
           sizeof(WASMComponentCanonSection));
    canon_section->parsed.canon_section->count = 1;
    canon_section->parsed.canon_section->canons =
        (WASMComponentCanon *)wasm_runtime_malloc(sizeof(WASMComponentCanon));
    if (!canon_section->parsed.canon_section->canons) {
        return false;
    }
    memset(canon_section->parsed.canon_section->canons, 0,
           sizeof(WASMComponentCanon));
    canon_section->parsed.canon_section->canons[0].tag = WASM_COMP_CANON_LIFT;
    canon_section->parsed.canon_section->canons[0].canon_data.lift.core_func_idx =
        aliased_core_func_idx;
    canon_section->parsed.canon_section->canons[0].canon_data.lift.type_idx =
        lift_type_idx;

    export_section->id = WASM_COMP_SECTION_EXPORTS;
    export_section->parsed.export_section =
        (WASMComponentExportSection *)wasm_runtime_malloc(
            sizeof(WASMComponentExportSection));
    if (!export_section->parsed.export_section) {
        return false;
    }
    memset(export_section->parsed.export_section, 0,
           sizeof(WASMComponentExportSection));
    export_section->parsed.export_section->count = 1;
    export_section->parsed.export_section->exports =
        (WASMComponentExport *)wasm_runtime_malloc(sizeof(WASMComponentExport));
    if (!export_section->parsed.export_section->exports) {
        return false;
    }
    memset(export_section->parsed.export_section->exports, 0,
           sizeof(WASMComponentExport));
    export_section->parsed.export_section->exports[0].export_name =
        create_export_name(component_export_name);
    export_section->parsed.export_section->exports[0].sort_idx =
        create_sort_idx(WASM_COMP_SORT_FUNC, lifted_func_idx);

    return export_section->parsed.export_section->exports[0].export_name
           && export_section->parsed.export_section->exports[0].sort_idx;
}

static WASMComponentValueType
make_component_primitive_value_type(WASMComponentPrimValType prim_type);

struct TestComponentFuncParamSpec {
    const char *name;
    WASMComponentValueType value_type;
};

static int32_t
append_component_func_type(
    WASMComponentModule *component_module,
    const std::vector<TestComponentFuncParamSpec> &params,
    const std::optional<WASMComponentValueType> &result_type)
{
    WASMComponent *component = &component_module->component;
    WASMComponentSection *type_section_ref = nullptr;
    uint32_t type_base_idx = 0;
    uint32_t total_type_count = 0;
    auto *func_type = (WASMComponentFuncType *)wasm_runtime_malloc(
        sizeof(WASMComponentFuncType));

    if (!func_type) {
        return -1;
    }
    memset(func_type, 0, sizeof(WASMComponentFuncType));

    for (uint32_t i = 0; i < component->section_count; i++) {
        auto *section = &component->sections[i];
        if (section->id != WASM_COMP_SECTION_TYPE || !section->parsed.type_section) {
            continue;
        }
        type_section_ref = section;
        type_base_idx = total_type_count;
        total_type_count += section->parsed.type_section->count;
    }

    if (!type_section_ref || !type_section_ref->parsed.type_section) {
        return -1;
    }

    if (!params.empty()) {
        func_type->params = (WASMComponentParamList *)wasm_runtime_malloc(
            sizeof(WASMComponentParamList));
        if (!func_type->params) {
            return -1;
        }
        memset(func_type->params, 0, sizeof(WASMComponentParamList));
        func_type->params->count = (uint32_t)params.size();
        func_type->params->params = (WASMComponentLabelValType *)wasm_runtime_malloc(
            sizeof(WASMComponentLabelValType) * func_type->params->count);
        if (!func_type->params->params) {
            return -1;
        }
        memset(func_type->params->params, 0,
               sizeof(WASMComponentLabelValType) * func_type->params->count);
        for (uint32_t i = 0; i < func_type->params->count; i++) {
            char label_name[16];
            snprintf(label_name, sizeof(label_name), "p%u", i);
            func_type->params->params[i].label =
                clone_core_name(params[i].name ? params[i].name : label_name);
            func_type->params->params[i].value_type =
                (WASMComponentValueType *)wasm_runtime_malloc(
                    sizeof(WASMComponentValueType));
            if (!func_type->params->params[i].label
                || !func_type->params->params[i].value_type) {
                return -1;
            }
            *func_type->params->params[i].value_type = params[i].value_type;
        }
    }

    func_type->results = (WASMComponentResultList *)wasm_runtime_malloc(
        sizeof(WASMComponentResultList));
    if (!func_type->results) {
        return -1;
    }
    memset(func_type->results, 0, sizeof(WASMComponentResultList));
    if (result_type.has_value()) {
        func_type->results->tag = WASM_COMP_RESULT_LIST_WITH_TYPE;
        func_type->results->results =
            (WASMComponentValueType *)wasm_runtime_malloc(
                sizeof(WASMComponentValueType));
        if (!func_type->results->results) {
            return -1;
        }
        *func_type->results->results = result_type.value();
    }
    else {
        func_type->results->tag = WASM_COMP_RESULT_LIST_EMPTY;
    }

    auto *type_section = type_section_ref->parsed.type_section;
    const uint32_t new_count = type_section->count + 1;
    auto *new_types = (WASMComponentTypes *)wasm_runtime_malloc(
        sizeof(WASMComponentTypes) * new_count);
    if (!new_types) {
        return -1;
    }

    memset(new_types, 0, sizeof(WASMComponentTypes) * new_count);
    memcpy(new_types, type_section->types,
           sizeof(WASMComponentTypes) * type_section->count);
    new_types[type_section->count].tag = WASM_COMP_FUNC_TYPE;
    new_types[type_section->count].type.func_type = func_type;

    if (type_section->types) {
        wasm_runtime_free(type_section->types);
    }
    type_section->types = new_types;
    type_section->count = new_count;
    return (int32_t)(type_base_idx + new_count - 1);
}

static int32_t
append_component_scalar_func_type(
    WASMComponentModule *component_module,
    const std::vector<WASMComponentPrimValType> &param_types,
    const std::optional<WASMComponentPrimValType> &result_type)
{
    std::vector<TestComponentFuncParamSpec> params;

    params.reserve(param_types.size());
    for (uint32_t i = 0; i < param_types.size(); i++) {
        params.push_back(
            { nullptr, make_component_primitive_value_type(param_types[i]) });
    }

    return append_component_func_type(
        component_module, params,
        result_type.has_value()
            ? std::optional<WASMComponentValueType>(
                  make_component_primitive_value_type(result_type.value()))
            : std::nullopt);
}

static bool
clone_supported_value_type_into_component(
    WASMComponent *target_component, const WASMComponent *source_component,
    const WASMComponentValueType *source_value_type,
    WASMComponentValueType *out_value_type);

static uint32_t
append_func_type_to_type_section(WASMComponentTypeSection *type_section,
                                 WASMComponentFuncType *func_type)
{
    auto *new_types = type_section
                          ? (WASMComponentTypes *)wasm_runtime_malloc(
                                sizeof(WASMComponentTypes)
                                * (type_section->count + 1))
                          : nullptr;
    const uint32_t func_type_idx = type_section ? type_section->count : 0;

    if (!type_section || !func_type || !new_types) {
        return UINT32_MAX;
    }

    memset(new_types, 0,
           sizeof(WASMComponentTypes) * (type_section->count + 1));
    memcpy(new_types, type_section->types,
           sizeof(WASMComponentTypes) * type_section->count);
    new_types[type_section->count].tag = WASM_COMP_FUNC_TYPE;
    new_types[type_section->count].type.func_type = func_type;

    if (type_section->types) {
        wasm_runtime_free(type_section->types);
    }
    type_section->types = new_types;
    type_section->count++;
    return func_type_idx;
}

static WASMComponentFuncType *
clone_component_func_type(const WASMComponent *source_component,
                          WASMComponent *target_component,
                          const WASMComponentFuncType *src)
{
    auto *func_type = (WASMComponentFuncType *)wasm_runtime_malloc(
        sizeof(WASMComponentFuncType));
    if (!func_type) {
        return nullptr;
    }
    memset(func_type, 0, sizeof(WASMComponentFuncType));

    if (src && src->params) {
        func_type->params = (WASMComponentParamList *)wasm_runtime_malloc(
            sizeof(WASMComponentParamList));
        if (!func_type->params) {
            return nullptr;
        }
        memset(func_type->params, 0, sizeof(WASMComponentParamList));
        func_type->params->count = src->params->count;
        if (func_type->params->count > 0) {
            func_type->params->params =
                (WASMComponentLabelValType *)wasm_runtime_malloc(
                    sizeof(WASMComponentLabelValType) * func_type->params->count);
            if (!func_type->params->params) {
                return nullptr;
            }
            memset(func_type->params->params, 0,
                   sizeof(WASMComponentLabelValType) * func_type->params->count);
            for (uint32_t i = 0; i < func_type->params->count; i++) {
                const char *label = src->params->params[i].label
                                        ? src->params->params[i].label->name
                                        : "p";
                func_type->params->params[i].label = clone_core_name(label);
                func_type->params->params[i].value_type =
                    (WASMComponentValueType *)wasm_runtime_malloc(
                        sizeof(WASMComponentValueType));
                if (!func_type->params->params[i].label
                    || !func_type->params->params[i].value_type) {
                    return nullptr;
                }
                if (!clone_supported_value_type_into_component(
                        target_component, source_component,
                        src->params->params[i].value_type,
                        func_type->params->params[i].value_type)) {
                    return nullptr;
                }
            }
        }
    }

    func_type->results = (WASMComponentResultList *)wasm_runtime_malloc(
        sizeof(WASMComponentResultList));
    if (!func_type->results) {
        return nullptr;
    }
    memset(func_type->results, 0, sizeof(WASMComponentResultList));
    if (!src || !src->results
        || src->results->tag == WASM_COMP_RESULT_LIST_EMPTY
        || !src->results->results) {
        func_type->results->tag = WASM_COMP_RESULT_LIST_EMPTY;
    }
    else {
        func_type->results->tag = src->results->tag;
        func_type->results->results =
            (WASMComponentValueType *)wasm_runtime_malloc(
                sizeof(WASMComponentValueType));
        if (!func_type->results->results) {
            return nullptr;
        }
        if (!clone_supported_value_type_into_component(
                target_component, source_component, src->results->results,
                func_type->results->results)) {
            return nullptr;
        }
    }

    return func_type;
}

static bool
init_nested_single_func_instance_type_section(
    WASMComponentModule *component_module, WASMComponent *target_component,
    WASMComponentTypeSection *type_section, const char *function_name,
    uint32_t outer_func_type_idx)
{
    WASMComponentFuncType *src_func_type =
        lookup_local_component_func_type(component_module, outer_func_type_idx);
    WASMComponentFuncType *cloned_func_type =
        src_func_type ? clone_component_func_type(&component_module->component,
                                                  target_component,
                                                  src_func_type)
                      : nullptr;
    WASMComponentInstType *instance_type =
        (WASMComponentInstType *)wasm_runtime_malloc(sizeof(WASMComponentInstType));
    uint32_t local_func_type_idx = UINT32_MAX;
    WASMComponentTypes *new_types;

    if (!type_section || !target_component || !src_func_type || !cloned_func_type
        || !instance_type) {
        return false;
    }

    memset(type_section, 0, sizeof(WASMComponentTypeSection));
    memset(instance_type, 0, sizeof(WASMComponentInstType));
    instance_type->count = 1;
    instance_type->instance_decls =
        (WASMComponentInstDecl *)wasm_runtime_malloc(sizeof(WASMComponentInstDecl));
    if (!instance_type->instance_decls) {
        return false;
    }
    memset(instance_type->instance_decls, 0, sizeof(WASMComponentInstDecl));
    instance_type->instance_decls[0].tag =
        WASM_COMP_COMPONENT_DECL_INSTANCE_EXPORTDECL;
    instance_type->instance_decls[0].decl.export_decl =
        (WASMComponentComponentDeclExport *)wasm_runtime_malloc(
            sizeof(WASMComponentComponentDeclExport));
    if (!instance_type->instance_decls[0].decl.export_decl) {
        return false;
    }
    memset(instance_type->instance_decls[0].decl.export_decl, 0,
           sizeof(WASMComponentComponentDeclExport));
    instance_type->instance_decls[0].decl.export_decl->export_name =
        create_export_name(function_name);
    local_func_type_idx = append_func_type_to_type_section(type_section, cloned_func_type);
    instance_type->instance_decls[0].decl.export_decl->extern_desc =
        local_func_type_idx == UINT32_MAX ? nullptr
                                          : create_func_extern_desc(local_func_type_idx);
    if (!instance_type->instance_decls[0].decl.export_decl->export_name
        || !instance_type->instance_decls[0].decl.export_decl->extern_desc) {
        return false;
    }

    new_types = (WASMComponentTypes *)wasm_runtime_malloc(
        sizeof(WASMComponentTypes) * (type_section->count + 1));
    if (!new_types) {
        return false;
    }
    memset(new_types, 0, sizeof(WASMComponentTypes) * (type_section->count + 1));
    memcpy(new_types, type_section->types,
           sizeof(WASMComponentTypes) * type_section->count);
    new_types[type_section->count].tag = WASM_COMP_INSTANCE_TYPE;
    new_types[type_section->count].type.instance_type = instance_type;
    if (type_section->types) {
        wasm_runtime_free(type_section->types);
    }
    type_section->types = new_types;
    type_section->count++;
    return true;
}

static bool
append_top_level_function_export_alias(WASMComponentModule *component_module,
                                       const char *instance_export_name,
                                       const char *function_name,
                                       const char *top_export_name)
{
    WASMComponent *component = &component_module->component;
    const uint32_t alias_func_idx =
        count_top_level_sort_entries(component, WASM_COMP_SORT_FUNC);
    int32_t instance_idx = find_top_level_export_sort_index(
        component_module, instance_export_name, WASM_COMP_SORT_INSTANCE);
    const uint32_t old_count = component->section_count;
    auto *new_sections = (WASMComponentSection *)wasm_runtime_malloc(
        sizeof(WASMComponentSection) * (old_count + 2));
    if (instance_idx < 0) {
        const uint32_t instance_count =
            count_top_level_sort_entries(component, WASM_COMP_SORT_INSTANCE);
        if (instance_count == 0) {
            return false;
        }
        instance_idx = (int32_t)(instance_count - 1);
    }
    if (!new_sections) {
        return false;
    }

    memset(new_sections, 0, sizeof(WASMComponentSection) * (old_count + 2));
    memcpy(new_sections, component->sections,
           sizeof(WASMComponentSection) * old_count);
    wasm_runtime_free(component->sections);
    component->sections = new_sections;
    component->section_count = old_count + 2;

    auto *alias_section = &component->sections[old_count];
    auto *export_section = &component->sections[old_count + 1];

    alias_section->id = WASM_COMP_SECTION_ALIASES;
    alias_section->parsed.alias_section =
        (WASMComponentAliasSection *)wasm_runtime_malloc(
            sizeof(WASMComponentAliasSection));
    if (!alias_section->parsed.alias_section) {
        return false;
    }
    memset(alias_section->parsed.alias_section, 0,
           sizeof(WASMComponentAliasSection));
    alias_section->parsed.alias_section->count = 1;
    alias_section->parsed.alias_section->aliases =
        (WASMComponentAliasDefinition *)wasm_runtime_malloc(
            sizeof(WASMComponentAliasDefinition));
    if (!alias_section->parsed.alias_section->aliases) {
        return false;
    }
    memset(alias_section->parsed.alias_section->aliases, 0,
           sizeof(WASMComponentAliasDefinition));
    alias_section->parsed.alias_section->aliases[0].sort =
        create_sort(WASM_COMP_SORT_FUNC);
    alias_section->parsed.alias_section->aliases[0].alias_target_type =
        WASM_COMP_ALIAS_TARGET_EXPORT;
    alias_section->parsed.alias_section->aliases[0].target.exported.instance_idx =
        (uint32_t)instance_idx;
    alias_section->parsed.alias_section->aliases[0].target.exported.name =
        clone_core_name(function_name);
    if (!alias_section->parsed.alias_section->aliases[0].sort
        || !alias_section->parsed.alias_section->aliases[0]
                .target.exported.name) {
        return false;
    }

    export_section->id = WASM_COMP_SECTION_EXPORTS;
    export_section->parsed.export_section =
        (WASMComponentExportSection *)wasm_runtime_malloc(
            sizeof(WASMComponentExportSection));
    if (!export_section->parsed.export_section) {
        return false;
    }
    memset(export_section->parsed.export_section, 0,
           sizeof(WASMComponentExportSection));
    export_section->parsed.export_section->count = 1;
    export_section->parsed.export_section->exports =
        (WASMComponentExport *)wasm_runtime_malloc(sizeof(WASMComponentExport));
    if (!export_section->parsed.export_section->exports) {
        return false;
    }
    memset(export_section->parsed.export_section->exports, 0,
           sizeof(WASMComponentExport));
    export_section->parsed.export_section->exports[0].export_name =
        create_export_name(top_export_name);
    export_section->parsed.export_section->exports[0].sort_idx =
        create_sort_idx(WASM_COMP_SORT_FUNC, alias_func_idx);

    return export_section->parsed.export_section->exports[0].export_name
           && export_section->parsed.export_section->exports[0].sort_idx;
}

static bool
rewrite_component_func_type_from_source(WASMComponent *target_component,
                                         const WASMComponent *source_component,
                                         const WASMComponentFuncType *source_func_type,
                                         WASMComponentFuncType *target_func_type)
{
    const uint32_t source_param_count =
        source_func_type && source_func_type->params
            ? source_func_type->params->count
            : 0;

    if (!target_component || !source_component || !source_func_type
        || !target_func_type || (source_param_count > 0 && !target_func_type->params)
        || (source_param_count > 0
            && source_param_count > target_func_type->params->count)
        || !target_func_type->results || !source_func_type->results) {
        return false;
    }

    if (target_func_type->params) {
        target_func_type->params->count = source_param_count;
    }
    for (uint32_t i = 0; i < source_param_count; i++) {
        if (!target_func_type->params->params[i].value_type
            || !clone_supported_value_type_into_component(
                target_component, source_component,
                source_func_type->params->params[i].value_type,
                target_func_type->params->params[i].value_type)) {
            return false;
        }
    }

    target_func_type->results->tag = source_func_type->results->tag;
    if (source_func_type->results->tag == WASM_COMP_RESULT_LIST_WITH_TYPE) {
        if (!target_func_type->results->results
            || !clone_supported_value_type_into_component(
                target_component, source_component,
                source_func_type->results->results,
                target_func_type->results->results)) {
            return false;
        }
    }

    return true;
}

static bool
rewrite_existing_nested_component_func_types(WASMComponent *component,
                                             const WASMComponent *source_component,
                                             const WASMComponentFuncType *source_func_type)
{
    if (!component || !source_component || !source_func_type) {
        return false;
    }

    for (uint32_t i = 0; i < component->section_count; i++) {
        WASMComponentSection *section = &component->sections[i];

        if (section->id == WASM_COMP_SECTION_TYPE && section->parsed.type_section) {
            for (uint32_t type_idx = 0; type_idx < section->parsed.type_section->count;
                 type_idx++) {
                WASMComponentTypes *type_entry =
                    &section->parsed.type_section->types[type_idx];
                if (type_entry->tag == WASM_COMP_FUNC_TYPE
                    && !rewrite_component_func_type_from_source(
                        component, source_component, source_func_type,
                        type_entry->type.func_type)) {
                    return false;
                }
            }
        }
        else if (section->id == WASM_COMP_SECTION_COMPONENT
                 && section->parsed.component
                 && !rewrite_existing_nested_component_func_types(
                     section->parsed.component, source_component,
                     source_func_type)) {
            return false;
        }
    }

    return true;
}

static bool
propagate_first_canon_lift_signature_to_existing_nested_components(
    WASMComponentModule *component_module,
    const WASMComponentFuncType *mutated_func_type)
{
    WASMComponent *component = component_module ? &component_module->component : nullptr;

    if (!component || !mutated_func_type) {
        return false;
    }

    for (uint32_t i = 0; i < component->section_count; i++) {
        WASMComponentSection *section = &component->sections[i];
        if (section->id == WASM_COMP_SECTION_COMPONENT && section->parsed.component
            && !rewrite_existing_nested_component_func_types(
                section->parsed.component, component, mutated_func_type)) {
            return false;
        }
    }

    return true;
}

static bool
configure_first_canon_lift_for_utf8_string(WASMComponentModule *component_module,
                                           bool string_result)
{
    WASMComponentCanon *canon = find_first_canon_lift(component_module);
    WASMComponentFuncType *func_type = canon
                                           ? lookup_local_component_func_type(
                                                 component_module,
                                                 canon->canon_data.lift.type_idx)
                                           : nullptr;

    if (!canon || !func_type || !func_type->params || func_type->params->count == 0
        || !func_type->params->params[0].value_type || !func_type->results
        || func_type->results->tag != WASM_COMP_RESULT_LIST_WITH_TYPE
        || !func_type->results->results) {
        return false;
    }

    func_type->params->count = 1;
    func_type->params->params[0].value_type->type = WASM_COMP_VAL_TYPE_PRIMVAL;
    func_type->params->params[0].value_type->type_specific.primval_type =
        WASM_COMP_PRIMVAL_STRING;

    func_type->results->results->type = WASM_COMP_VAL_TYPE_PRIMVAL;
    func_type->results->results->type_specific.primval_type =
        string_result ? WASM_COMP_PRIMVAL_STRING : WASM_COMP_PRIMVAL_S32;

    canon->canon_data.lift.canon_opts =
        (WASMComponentCanonOpts *)wasm_runtime_malloc(
            sizeof(WASMComponentCanonOpts));
    if (!canon->canon_data.lift.canon_opts) {
        return false;
    }
    memset(canon->canon_data.lift.canon_opts, 0, sizeof(WASMComponentCanonOpts));
    canon->canon_data.lift.canon_opts->canon_opts_count = 3;
    canon->canon_data.lift.canon_opts->canon_opts =
        (WASMComponentCanonOpt *)wasm_runtime_malloc(
            sizeof(WASMComponentCanonOpt) * 3);
    if (!canon->canon_data.lift.canon_opts->canon_opts) {
        return false;
    }
    memset(canon->canon_data.lift.canon_opts->canon_opts, 0,
           sizeof(WASMComponentCanonOpt) * 3);
    canon->canon_data.lift.canon_opts->canon_opts[0].tag =
        WASM_COMP_CANON_OPT_STRING_UTF8;
    canon->canon_data.lift.canon_opts->canon_opts[1].tag =
        WASM_COMP_CANON_OPT_MEMORY;
    canon->canon_data.lift.canon_opts->canon_opts[1].payload.memory.mem_idx = 0;
    canon->canon_data.lift.canon_opts->canon_opts[2].tag =
        WASM_COMP_CANON_OPT_REALLOC;
    canon->canon_data.lift.canon_opts->canon_opts[2].payload.realloc_opt.func_idx =
        2;
    return propagate_first_canon_lift_signature_to_existing_nested_components(
        component_module, func_type);
}

static int32_t
append_component_list_type(WASMComponentModule *component_module,
                           WASMComponentPrimValType element_prim_type,
                           bool fixed_length, uint32_t fixed_len)
{
    WASMComponent *component = &component_module->component;
    WASMComponentSection *type_section_ref = nullptr;
    uint32_t type_base_idx = 0;
    uint32_t total_type_count = 0;

    for (uint32_t i = 0; i < component->section_count; i++) {
        auto *section = &component->sections[i];
        if (section->id != WASM_COMP_SECTION_TYPE || !section->parsed.type_section) {
            continue;
        }
        type_section_ref = section;
        type_base_idx = total_type_count;
        total_type_count += section->parsed.type_section->count;
    }

    if (!type_section_ref || !type_section_ref->parsed.type_section) {
        return -1;
    }

    auto *type_section = type_section_ref->parsed.type_section;
    const uint32_t new_count = type_section->count + 1;
    auto *new_types = (WASMComponentTypes *)wasm_runtime_malloc(
        sizeof(WASMComponentTypes) * new_count);
    if (!new_types) {
        return -1;
    }

    memset(new_types, 0, sizeof(WASMComponentTypes) * new_count);
    memcpy(new_types, type_section->types,
           sizeof(WASMComponentTypes) * type_section->count);

    auto *new_entry = &new_types[type_section->count];
    new_entry->tag = WASM_COMP_DEF_TYPE;
    new_entry->type.def_val_type = (WASMComponentDefValType *)wasm_runtime_malloc(
        sizeof(WASMComponentDefValType));
    if (!new_entry->type.def_val_type) {
        wasm_runtime_free(new_types);
        return -1;
    }
    memset(new_entry->type.def_val_type, 0, sizeof(WASMComponentDefValType));

    if (fixed_length) {
        new_entry->type.def_val_type->tag = WASM_COMP_DEF_VAL_LIST_LEN;
        new_entry->type.def_val_type->def_val.list_len =
            (WASMComponentListLenType *)wasm_runtime_malloc(
                sizeof(WASMComponentListLenType));
        if (!new_entry->type.def_val_type->def_val.list_len) {
            wasm_runtime_free(new_entry->type.def_val_type);
            wasm_runtime_free(new_types);
            return -1;
        }
        memset(new_entry->type.def_val_type->def_val.list_len, 0,
               sizeof(WASMComponentListLenType));
        new_entry->type.def_val_type->def_val.list_len->len = fixed_len;
        new_entry->type.def_val_type->def_val.list_len->element_type =
            (WASMComponentValueType *)wasm_runtime_malloc(
                sizeof(WASMComponentValueType));
        if (!new_entry->type.def_val_type->def_val.list_len->element_type) {
            wasm_runtime_free(new_entry->type.def_val_type->def_val.list_len);
            wasm_runtime_free(new_entry->type.def_val_type);
            wasm_runtime_free(new_types);
            return -1;
        }
        memset(new_entry->type.def_val_type->def_val.list_len->element_type, 0,
               sizeof(WASMComponentValueType));
        new_entry->type.def_val_type->def_val.list_len->element_type->type =
            WASM_COMP_VAL_TYPE_PRIMVAL;
        new_entry->type.def_val_type->def_val.list_len->element_type->type_specific
            .primval_type = element_prim_type;
    }
    else {
        new_entry->type.def_val_type->tag = WASM_COMP_DEF_VAL_LIST;
        new_entry->type.def_val_type->def_val.list =
            (WASMComponentListType *)wasm_runtime_malloc(
                sizeof(WASMComponentListType));
        if (!new_entry->type.def_val_type->def_val.list) {
            wasm_runtime_free(new_entry->type.def_val_type);
            wasm_runtime_free(new_types);
            return -1;
        }
        memset(new_entry->type.def_val_type->def_val.list, 0,
               sizeof(WASMComponentListType));
        new_entry->type.def_val_type->def_val.list->element_type =
            (WASMComponentValueType *)wasm_runtime_malloc(
                sizeof(WASMComponentValueType));
        if (!new_entry->type.def_val_type->def_val.list->element_type) {
            wasm_runtime_free(new_entry->type.def_val_type->def_val.list);
            wasm_runtime_free(new_entry->type.def_val_type);
            wasm_runtime_free(new_types);
            return -1;
        }
        memset(new_entry->type.def_val_type->def_val.list->element_type, 0,
               sizeof(WASMComponentValueType));
        new_entry->type.def_val_type->def_val.list->element_type->type =
            WASM_COMP_VAL_TYPE_PRIMVAL;
        new_entry->type.def_val_type->def_val.list->element_type->type_specific
            .primval_type = element_prim_type;
    }

    if (type_section->types) {
        wasm_runtime_free(type_section->types);
    }
    type_section->types = new_types;
    type_section->count = new_count;
    return (int32_t)(type_base_idx + new_count - 1);
}

static WASMComponentValueType
make_component_primitive_value_type(WASMComponentPrimValType prim_type)
{
    WASMComponentValueType value_type = {};
    value_type.type = WASM_COMP_VAL_TYPE_PRIMVAL;
    value_type.type_specific.primval_type = prim_type;
    return value_type;
}

static WASMComponentValueType
make_component_type_index_value_type(uint32_t type_idx)
{
    WASMComponentValueType value_type = {};
    value_type.type = WASM_COMP_VAL_TYPE_IDX;
    value_type.type_specific.type_idx = type_idx;
    return value_type;
}

static bool
configure_canon_lift_param_type_idx(WASMComponentModule *component_module,
                                    WASMComponentCanon *canon,
                                    uint32_t param_idx,
                                    uint32_t param_type_idx,
                                    bool ensure_memory_opt,
                                    bool ensure_realloc_opt);

static int32_t
append_component_def_val_type(WASMComponentModule *component_module,
                              WASMComponentDefValType *def_val_type)
{
    WASMComponent *component = &component_module->component;
    WASMComponentSection *type_section_ref = nullptr;
    uint32_t type_base_idx = 0;
    uint32_t total_type_count = 0;

    for (uint32_t i = 0; i < component->section_count; i++) {
        auto *section = &component->sections[i];
        if (section->id != WASM_COMP_SECTION_TYPE || !section->parsed.type_section) {
            continue;
        }
        type_section_ref = section;
        type_base_idx = total_type_count;
        total_type_count += section->parsed.type_section->count;
    }

    if (!type_section_ref || !type_section_ref->parsed.type_section
        || !def_val_type) {
        return -1;
    }

    auto *type_section = type_section_ref->parsed.type_section;
    const uint32_t new_count = type_section->count + 1;
    auto *new_types = (WASMComponentTypes *)wasm_runtime_malloc(
        sizeof(WASMComponentTypes) * new_count);
    if (!new_types) {
        return -1;
    }

    memset(new_types, 0, sizeof(WASMComponentTypes) * new_count);
    memcpy(new_types, type_section->types,
           sizeof(WASMComponentTypes) * type_section->count);

    new_types[type_section->count].tag = WASM_COMP_DEF_TYPE;
    new_types[type_section->count].type.def_val_type = def_val_type;

    if (type_section->types) {
        wasm_runtime_free(type_section->types);
    }
    type_section->types = new_types;
    type_section->count = new_count;
    return (int32_t)(type_base_idx + new_count - 1);
}

struct TestComponentRecordFieldSpec {
    const char *name;
    WASMComponentValueType value_type;
};

static int32_t
append_component_tuple_type(
    WASMComponentModule *component_module,
    const std::vector<WASMComponentValueType> &element_types)
{
    auto *def_val_type = (WASMComponentDefValType *)wasm_runtime_malloc(
        sizeof(WASMComponentDefValType));
    auto *tuple_type = (WASMComponentTupleType *)wasm_runtime_malloc(
        sizeof(WASMComponentTupleType));
    if (!def_val_type || !tuple_type || element_types.empty()) {
        return -1;
    }

    memset(def_val_type, 0, sizeof(WASMComponentDefValType));
    memset(tuple_type, 0, sizeof(WASMComponentTupleType));
    tuple_type->count = (uint32_t)element_types.size();
    tuple_type->element_types = (WASMComponentValueType *)wasm_runtime_malloc(
        sizeof(WASMComponentValueType) * tuple_type->count);
    if (!tuple_type->element_types) {
        return -1;
    }

    memcpy(tuple_type->element_types, element_types.data(),
           sizeof(WASMComponentValueType) * tuple_type->count);
    def_val_type->tag = WASM_COMP_DEF_VAL_TUPLE;
    def_val_type->def_val.tuple = tuple_type;
    return append_component_def_val_type(component_module, def_val_type);
}

static int32_t
append_component_record_type(
    WASMComponentModule *component_module,
    const std::vector<TestComponentRecordFieldSpec> &fields)
{
    auto *def_val_type = (WASMComponentDefValType *)wasm_runtime_malloc(
        sizeof(WASMComponentDefValType));
    auto *record_type = (WASMComponentRecordType *)wasm_runtime_malloc(
        sizeof(WASMComponentRecordType));
    if (!def_val_type || !record_type || fields.empty()) {
        return -1;
    }

    memset(def_val_type, 0, sizeof(WASMComponentDefValType));
    memset(record_type, 0, sizeof(WASMComponentRecordType));
    record_type->count = (uint32_t)fields.size();
    record_type->fields = (WASMComponentLabelValType *)wasm_runtime_malloc(
        sizeof(WASMComponentLabelValType) * record_type->count);
    if (!record_type->fields) {
        return -1;
    }

    memset(record_type->fields, 0,
           sizeof(WASMComponentLabelValType) * record_type->count);
    for (uint32_t i = 0; i < record_type->count; i++) {
        record_type->fields[i].label = clone_core_name(fields[i].name);
        record_type->fields[i].value_type =
            (WASMComponentValueType *)wasm_runtime_malloc(
                sizeof(WASMComponentValueType));
        if (!record_type->fields[i].label || !record_type->fields[i].value_type) {
            return -1;
        }
        *record_type->fields[i].value_type = fields[i].value_type;
    }

    def_val_type->tag = WASM_COMP_DEF_VAL_RECORD;
    def_val_type->def_val.record = record_type;
    return append_component_def_val_type(component_module, def_val_type);
}

static bool
configure_canon_lift_param_type_idx(WASMComponentModule *component_module,
                                    WASMComponentCanon *canon,
                                    uint32_t param_idx,
                                    uint32_t param_type_idx,
                                    bool ensure_memory_opt,
                                    bool ensure_realloc_opt);

static bool
configure_first_canon_lift_for_defined_param(WASMComponentModule *component_module,
                                             uint32_t param_type_idx)
{
    WASMComponentCanon *canon = find_first_canon_lift(component_module);
    WASMComponentFuncType *func_type = canon
                                           ? lookup_local_component_func_type(
                                                 component_module,
                                                 canon->canon_data.lift.type_idx)
                                           : nullptr;

    if (!canon || !func_type || !func_type->params || func_type->params->count == 0) {
        return false;
    }

    func_type->params->count = 1;
    return configure_canon_lift_param_type_idx(component_module, canon, 0,
                                               param_type_idx, false, false)
           && propagate_first_canon_lift_signature_to_existing_nested_components(
               component_module, func_type);
}

static void
append_component_s32_payload(std::vector<uint8_t> *payload, int32_t value)
{
    int32_t current = value;
    bool done = false;

    while (!done) {
        uint8_t byte = (uint8_t)(current & 0x7f);
        current >>= 7;
        done = (current == 0 && (byte & 0x40) == 0)
               || (current == -1 && (byte & 0x40) != 0);
        if (!done) {
            byte |= 0x80;
        }
        payload->push_back(byte);
    }
}

static void
append_component_u64_payload(std::vector<uint8_t> *payload, uint64_t value)
{
    do {
        uint8_t byte = (uint8_t)(value & 0x7f);
        value >>= 7;
        if (value != 0) {
            byte |= 0x80;
        }
        payload->push_back(byte);
    } while (value != 0);
}

static void
append_component_f32_payload(std::vector<uint8_t> *payload, float value)
{
    uint8_t bytes[sizeof(value)];
    memcpy(bytes, &value, sizeof(bytes));
    payload->insert(payload->end(), bytes, bytes + sizeof(bytes));
}

static void
append_component_f64_payload(std::vector<uint8_t> *payload, double value)
{
    uint8_t bytes[sizeof(value)];
    memcpy(bytes, &value, sizeof(bytes));
    payload->insert(payload->end(), bytes, bytes + sizeof(bytes));
}

static void
append_component_string_payload(std::vector<uint8_t> *payload,
                                const std::string &value)
{
    uint32_t remaining = (uint32_t)value.size();

    do {
        uint8_t byte = (uint8_t)(remaining & 0x7f);
        remaining >>= 7;
        if (remaining != 0) {
            byte |= 0x80;
        }
        payload->push_back(byte);
    } while (remaining != 0);

    payload->insert(payload->end(), value.begin(), value.end());
}

static void
append_component_list_u8_payload(std::vector<uint8_t> *payload, const void *data,
                                 uint32_t size)
{
    append_component_u64_payload(payload, size);
    if (size > 0 && data) {
        const auto *bytes = (const uint8_t *)data;
        payload->insert(payload->end(), bytes, bytes + size);
    }
}

static void
append_component_list_scalar_payload(std::vector<uint8_t> *payload,
                                     uint32_t element_count, const void *data,
                                     uint32_t byte_size)
{
    append_component_u64_payload(payload, element_count);
    if (byte_size > 0 && data) {
        const auto *bytes = (const uint8_t *)data;
        payload->insert(payload->end(), bytes, bytes + byte_size);
    }
}

static int32_t
append_component_record_string_list_value_type(
    WASMComponentModule *component_module, bool fixed_length_list,
    uint32_t fixed_len, const char *rhs_field_name)
{
    const int32_t list_u8_type_idx = append_component_list_type(
        component_module, WASM_COMP_PRIMVAL_U8, fixed_length_list, fixed_len);
    if (list_u8_type_idx < 0) {
        return -1;
    }

    const int32_t inner_tuple_type_idx = append_component_tuple_type(
        component_module,
        { make_component_primitive_value_type(WASM_COMP_PRIMVAL_STRING),
          make_component_type_index_value_type((uint32_t)list_u8_type_idx) });
    if (inner_tuple_type_idx < 0) {
        return -1;
    }

    return append_component_record_type(
        component_module,
        { { "lhs", make_component_primitive_value_type(WASM_COMP_PRIMVAL_S32) },
          { rhs_field_name ? rhs_field_name : "rhs",
            make_component_type_index_value_type((uint32_t)inner_tuple_type_idx) } });
}

static bool
clone_supported_value_type_into_component(
    WASMComponent *target_component, const WASMComponent *source_component,
    const WASMComponentValueType *source_value_type,
    WASMComponentValueType *out_value_type)
{
    const WASMComponentTypes *type_entry;
    const WASMComponentDefValType *def_type;

    if (!target_component || !source_component || !source_value_type
        || !out_value_type) {
        return false;
    }

    if (source_value_type->type == WASM_COMP_VAL_TYPE_PRIMVAL) {
        *out_value_type = *source_value_type;
        return true;
    }

    type_entry = wasm_component_lookup_type(source_component,
                                            source_value_type->type_specific.type_idx);
    if (!type_entry || type_entry->tag != WASM_COMP_DEF_TYPE
        || !(def_type = type_entry->type.def_val_type)) {
        return false;
    }

    switch (def_type->tag) {
        case WASM_COMP_DEF_VAL_PRIMVAL:
            *out_value_type =
                make_component_primitive_value_type(def_type->def_val.primval);
            return true;
        case WASM_COMP_DEF_VAL_LIST:
        case WASM_COMP_DEF_VAL_LIST_LEN:
        {
            const WASMComponentValueType *element_type =
                def_type->tag == WASM_COMP_DEF_VAL_LIST
                    ? def_type->def_val.list
                          ? def_type->def_val.list->element_type
                          : nullptr
                    : def_type->def_val.list_len
                          ? def_type->def_val.list_len->element_type
                          : nullptr;
            WASMComponentPrimValType element_prim_type;
            WASMComponentModule target_module = {};
            int32_t type_idx;

            if (!element_type) {
                return false;
            }

            if (element_type->type == WASM_COMP_VAL_TYPE_PRIMVAL) {
                element_prim_type = (WASMComponentPrimValType)
                    element_type->type_specific.primval_type;
            }
            else {
                const WASMComponentTypes *element_entry =
                    wasm_component_lookup_type(
                        source_component, element_type->type_specific.type_idx);
                if (!element_entry || element_entry->tag != WASM_COMP_DEF_TYPE
                    || !element_entry->type.def_val_type
                    || element_entry->type.def_val_type->tag
                           != WASM_COMP_DEF_VAL_PRIMVAL) {
                    return false;
                }
                element_prim_type =
                    element_entry->type.def_val_type->def_val.primval;
            }

            target_module.component = *target_component;
            type_idx = append_component_list_type(
                &target_module, element_prim_type,
                def_type->tag == WASM_COMP_DEF_VAL_LIST_LEN,
                def_type->tag == WASM_COMP_DEF_VAL_LIST_LEN
                    ? def_type->def_val.list_len->len
                    : 0);
            if (type_idx < 0) {
                return false;
            }

            *target_component = target_module.component;
            *out_value_type = make_component_type_index_value_type((uint32_t)type_idx);
            return true;
        }
        case WASM_COMP_DEF_VAL_TUPLE:
        {
            WASMComponentModule target_module = {};
            std::vector<WASMComponentValueType> element_types;
            int32_t type_idx;

            if (!def_type->def_val.tuple) {
                return false;
            }

            for (uint32_t i = 0; i < def_type->def_val.tuple->count; i++) {
                WASMComponentValueType nested_value_type = {};
                if (!clone_supported_value_type_into_component(
                        target_component, source_component,
                        &def_type->def_val.tuple->element_types[i],
                        &nested_value_type)) {
                    return false;
                }
                element_types.push_back(nested_value_type);
            }

            target_module.component = *target_component;
            type_idx = append_component_tuple_type(&target_module, element_types);
            if (type_idx < 0) {
                return false;
            }

            *target_component = target_module.component;
            *out_value_type = make_component_type_index_value_type((uint32_t)type_idx);
            return true;
        }
        case WASM_COMP_DEF_VAL_RECORD:
        {
            WASMComponentModule target_module = {};
            std::vector<TestComponentRecordFieldSpec> fields;
            int32_t type_idx;

            if (!def_type->def_val.record) {
                return false;
            }

            for (uint32_t i = 0; i < def_type->def_val.record->count; i++) {
                WASMComponentValueType nested_value_type = {};
                const char *field_name =
                    def_type->def_val.record->fields[i].label
                    && def_type->def_val.record->fields[i].label->name
                        ? def_type->def_val.record->fields[i].label->name
                        : nullptr;

                if (!field_name
                    || !clone_supported_value_type_into_component(
                        target_component, source_component,
                        def_type->def_val.record->fields[i].value_type,
                        &nested_value_type)) {
                    return false;
                }

                fields.push_back({ field_name, nested_value_type });
            }

            target_module.component = *target_component;
            type_idx = append_component_record_type(&target_module, fields);
            if (type_idx < 0) {
                return false;
            }

            *target_component = target_module.component;
            *out_value_type = make_component_type_index_value_type((uint32_t)type_idx);
            return true;
        }
        default:
            return false;
    }
}

static void
append_component_record_string_list_payload(std::vector<uint8_t> *payload,
                                            int32_t lhs,
                                            const std::string &rhs_string,
                                            const void *rhs_bytes,
                                            uint32_t rhs_size)
{
    append_component_s32_payload(payload, lhs);
    append_component_string_payload(payload, rhs_string);
    append_component_list_u8_payload(payload, rhs_bytes, rhs_size);
}

static bool
ensure_canon_lift_memory_opt(WASMComponentCanon *canon, uint32_t mem_idx)
{
    if (!canon || canon->tag != WASM_COMP_CANON_LIFT) {
        return false;
    }

    if (!canon->canon_data.lift.canon_opts) {
        canon->canon_data.lift.canon_opts =
            (WASMComponentCanonOpts *)wasm_runtime_malloc(
                sizeof(WASMComponentCanonOpts));
        if (!canon->canon_data.lift.canon_opts) {
            return false;
        }
        memset(canon->canon_data.lift.canon_opts, 0, sizeof(WASMComponentCanonOpts));
    }

    for (uint32_t i = 0; i < canon->canon_data.lift.canon_opts->canon_opts_count; i++) {
        if (canon->canon_data.lift.canon_opts->canon_opts[i].tag
            == WASM_COMP_CANON_OPT_MEMORY) {
            canon->canon_data.lift.canon_opts->canon_opts[i].payload.memory.mem_idx =
                mem_idx;
            return true;
        }
    }

    const uint32_t old_count = canon->canon_data.lift.canon_opts->canon_opts_count;
    auto *new_opts = (WASMComponentCanonOpt *)wasm_runtime_malloc(
        sizeof(WASMComponentCanonOpt) * (old_count + 1));
    if (!new_opts) {
        return false;
    }

    memset(new_opts, 0, sizeof(WASMComponentCanonOpt) * (old_count + 1));
    if (old_count > 0 && canon->canon_data.lift.canon_opts->canon_opts) {
        memcpy(new_opts, canon->canon_data.lift.canon_opts->canon_opts,
               sizeof(WASMComponentCanonOpt) * old_count);
        wasm_runtime_free(canon->canon_data.lift.canon_opts->canon_opts);
    }

    new_opts[old_count].tag = WASM_COMP_CANON_OPT_MEMORY;
    new_opts[old_count].payload.memory.mem_idx = mem_idx;
    canon->canon_data.lift.canon_opts->canon_opts = new_opts;
    canon->canon_data.lift.canon_opts->canon_opts_count = old_count + 1;
    return true;
}

static bool
ensure_canon_lower_memory_opt(WASMComponentCanon *canon, uint32_t mem_idx)
{
    if (!canon || canon->tag != WASM_COMP_CANON_LOWER) {
        return false;
    }

    if (!canon->canon_data.lower.canon_opts) {
        canon->canon_data.lower.canon_opts =
            (WASMComponentCanonOpts *)wasm_runtime_malloc(
                sizeof(WASMComponentCanonOpts));
        if (!canon->canon_data.lower.canon_opts) {
            return false;
        }
        memset(canon->canon_data.lower.canon_opts, 0,
               sizeof(WASMComponentCanonOpts));
    }

    for (uint32_t i = 0; i < canon->canon_data.lower.canon_opts->canon_opts_count;
         i++) {
        if (canon->canon_data.lower.canon_opts->canon_opts[i].tag
            == WASM_COMP_CANON_OPT_MEMORY) {
            canon->canon_data.lower.canon_opts->canon_opts[i].payload.memory.mem_idx =
                mem_idx;
            return true;
        }
    }

    const uint32_t old_count = canon->canon_data.lower.canon_opts->canon_opts_count;
    auto *new_opts = (WASMComponentCanonOpt *)wasm_runtime_malloc(
        sizeof(WASMComponentCanonOpt) * (old_count + 1));
    if (!new_opts) {
        return false;
    }

    memset(new_opts, 0, sizeof(WASMComponentCanonOpt) * (old_count + 1));
    if (old_count > 0 && canon->canon_data.lower.canon_opts->canon_opts) {
        memcpy(new_opts, canon->canon_data.lower.canon_opts->canon_opts,
               sizeof(WASMComponentCanonOpt) * old_count);
        wasm_runtime_free(canon->canon_data.lower.canon_opts->canon_opts);
    }

    new_opts[old_count].tag = WASM_COMP_CANON_OPT_MEMORY;
    new_opts[old_count].payload.memory.mem_idx = mem_idx;
    canon->canon_data.lower.canon_opts->canon_opts = new_opts;
    canon->canon_data.lower.canon_opts->canon_opts_count = old_count + 1;
    return true;
}

